window.LUAU_VM_MODULES={"opcodes":"-- luau-vm/src/opcodes.lua\n-- Custom instruction set for the ferret VM.\n--\n-- Register-based. Operands are register indices unless noted. Multi-value\n-- calls/returns/varargs follow a Lua-style convention: a count field of 0 means\n-- \"up to the current frame top\" (set by a preceding multi-value producer), and\n-- a result count of 0 means \"produce all results and set top\". Everything else\n-- uses exact counts, which keeps the common case simple and fast.\n--\n-- Instructions are stored at compile time as tables {op=, a=, b=, c=, bx=, sbx=}\n-- for readability; the serializer packs them into a compact binary form.\n--\n-- Captured locals and upvalues are unified as \"cells\" (a 1-field box {v=...}),\n-- so closures never touch the parent's live registers  no open/closed upvalue\n-- machinery is required.\n\nlocal Op = {}\nlocal names = {}\nlocal n = 0\nlocal function def(name)\n  n = n + 1\n  Op[name] = n\n  names[n] = name\n  return n\nend\n\n--  data movement / constants \ndef('MOVE')      -- A B      R[A] = R[B]\ndef('LOADK')     -- A Bx     R[A] = K[Bx]\ndef('LOADINT')   -- A sBx    R[A] = sBx                (immediate small integer)\ndef('LOADBOOL')  -- A B      R[A] = (B ~= 0)\ndef('LOADNIL')   -- A B      R[A..A+B] = nil\n\n--  globals / environment \ndef('GETGLOBAL') -- A Bx     R[A] = ENV[K[Bx]]\ndef('SETGLOBAL') -- A Bx     ENV[K[Bx]] = R[A]\n\n--  cells (captured locals) & upvalues \ndef('NEWCELL')   -- A        R[A] = { v = R[A] }       (box a captured local)\ndef('GETCELL')   -- A B      R[A] = R[B].v\ndef('SETCELL')   -- A B      R[A].v = R[B]\ndef('GETUPVAL')  -- A B      R[A] = U[B].v\ndef('SETUPVAL')  -- A B      U[B].v = R[A]\n\n--  tables \ndef('NEWTABLE')  -- A        R[A] = {}\ndef('GETTABLE')  -- A B C    R[A] = R[B][R[C]]\ndef('SETTABLE')  -- A B C    R[A][R[B]] = R[C]\ndef('GETFIELD')  -- A B Bx   R[A] = R[B][K[Bx]]        (const-string key fast path)\ndef('SETFIELD')  -- A Bx C   R[A][K[Bx]] = R[C]\ndef('SELF')      -- A B C    R[A+1] = R[B]; R[A] = R[B][K[C]]  (method prep)\ndef('SETLIST')   -- A B C    R[A][C + i] = R[A+i], i=1..B (B=0 -> up to top)\n\n--  arithmetic (R[A] = R[B] op R[C]) \ndef('ADD'); def('SUB'); def('MUL'); def('DIV'); def('MOD'); def('POW'); def('IDIV')\n--  bitwise \ndef('BAND'); def('BOR'); def('BXOR'); def('SHL'); def('SHR')\n--  concat \ndef('CONCAT')    -- A B C    R[A] = R[B] .. R[B+1] .. ... .. R[C]\n--  unary \ndef('UNM'); def('NOT'); def('LEN'); def('BNOT')  -- A B   R[A] = op R[B]\n--  comparison (R[A] = R[B] op R[C]) \ndef('EQ'); def('LT'); def('LE')\n\n--  control flow \ndef('JMP')       -- sBx      pc += sBx\ndef('JMPIF')     -- A sBx    if truthy(R[A]) then pc += sBx\ndef('JMPIFNOT')  -- A sBx    if not truthy(R[A]) then pc += sBx\n\n--  calls / returns \ndef('CALL')      -- A B C    call R[A] with (B-1) args; keep (C-1) results (0 = to top)\ndef('TAILCALL')  -- A B      return R[A]((B-1) args)   (no host TCO; result-preserving)\ndef('RETURN')    -- A B      return R[A..A+B-2]        (B=0 -> to top)\n\n--  closures / varargs \ndef('CLOSURE')   -- A Bx     R[A] = closure(protos[Bx], captured upvals)\ndef('VARARG')    -- A B      R[A..A+B-2] = varargs     (B=0 -> to top)\n\n--  loops \ndef('FORPREP')   -- A sBx    numeric-for init; jump to loop test\ndef('FORLOOP')   -- A sBx    numeric-for step + test; jump back if continuing\ndef('TFORCALL')  -- A C      generic-for: call iterator, C results into R[A+3..]\ndef('TFORLOOP')  -- A sBx    generic-for: if R[A+1] ~= nil then R[A]=R[A+1]; pc += sBx\n\ndef('NOP')       -- (used by peephole/DCE)\n\n-- Operand layout per opcode: which instruction fields carry data. Used by the\n-- serializer for a compact, self-validating encoding, and as documentation.\nlocal A, AB, ABC = { 'a' }, { 'a', 'b' }, { 'a', 'b', 'c' }\nlocal operands = {\n  [Op.MOVE] = AB, [Op.LOADK] = { 'a', 'bx' }, [Op.LOADINT] = { 'a', 'sbx' },\n  [Op.LOADBOOL] = AB, [Op.LOADNIL] = AB,\n  [Op.GETGLOBAL] = { 'a', 'bx' }, [Op.SETGLOBAL] = { 'a', 'bx' },\n  [Op.NEWCELL] = A, [Op.GETCELL] = AB, [Op.SETCELL] = AB, [Op.GETUPVAL] = AB, [Op.SETUPVAL] = AB,\n  [Op.NEWTABLE] = A, [Op.GETTABLE] = ABC, [Op.SETTABLE] = ABC,\n  [Op.GETFIELD] = { 'a', 'b', 'bx' }, [Op.SETFIELD] = { 'a', 'bx', 'c' },\n  [Op.SELF] = ABC, [Op.SETLIST] = ABC,\n  [Op.ADD] = ABC, [Op.SUB] = ABC, [Op.MUL] = ABC, [Op.DIV] = ABC, [Op.MOD] = ABC,\n  [Op.POW] = ABC, [Op.IDIV] = ABC,\n  [Op.BAND] = ABC, [Op.BOR] = ABC, [Op.BXOR] = ABC, [Op.SHL] = ABC, [Op.SHR] = ABC,\n  [Op.CONCAT] = ABC,\n  [Op.UNM] = AB, [Op.NOT] = AB, [Op.LEN] = AB, [Op.BNOT] = AB,\n  [Op.EQ] = ABC, [Op.LT] = ABC, [Op.LE] = ABC,\n  [Op.JMP] = { 'sbx' }, [Op.JMPIF] = { 'a', 'sbx' }, [Op.JMPIFNOT] = { 'a', 'sbx' },\n  [Op.CALL] = ABC, [Op.TAILCALL] = AB, [Op.RETURN] = AB,\n  [Op.CLOSURE] = { 'a', 'bx' }, [Op.VARARG] = AB,\n  [Op.FORPREP] = { 'a', 'sbx' }, [Op.FORLOOP] = { 'a', 'sbx' },\n  [Op.TFORCALL] = { 'a', 'c' }, [Op.TFORLOOP] = { 'a', 'sbx' },\n  [Op.NOP] = {},\n}\n\nlocal Opcodes = { Op = Op, name = names, count = n, operands = operands }\n\nfunction Opcodes.mnemonic(op)\n  return names[op] or ('?' .. tostring(op))\nend\n\nreturn Opcodes\n","bitops":"-- luau-vm/src/bitops.lua\n-- Portable 32-bit bitwise ops. Uses bit32 when present (Luau, Lua 5.2); falls\n-- back to arithmetic otherwise (Lua 5.4 removed both bit32 and  crucially for\n-- source portability  we cannot write &|~<<>> operators in code that must also\n-- parse under Luau). 32-bit (bit32) semantics; document accordingly.\n\nlocal M = {}\n\nif bit32 then\n  M.band = bit32.band\n  M.bor = bit32.bor\n  M.bxor = bit32.bxor\n  M.lshift = bit32.lshift\n  M.rshift = bit32.rshift\n  M.bnot = bit32.bnot\nelse\n  local TWO32 = 4294967296\n  local function norm(x) x = math.floor(x) % TWO32; return x end\n  local function binop(a, b, f)\n    a = norm(a); b = norm(b)\n    local r, p = 0, 1\n    for _ = 0, 31 do\n      local x, y = a % 2, b % 2\n      if f(x, y) == 1 then r = r + p end\n      a = (a - x) / 2; b = (b - y) / 2; p = p * 2\n    end\n    return r\n  end\n  function M.band(a, b) return binop(a, b, function(x, y) return (x == 1 and y == 1) and 1 or 0 end) end\n  function M.bor(a, b) return binop(a, b, function(x, y) return (x == 1 or y == 1) and 1 or 0 end) end\n  function M.bxor(a, b) return binop(a, b, function(x, y) return (x ~= y) and 1 or 0 end) end\n  function M.lshift(a, n) return norm(norm(a) * (2 ^ n)) end\n  function M.rshift(a, n) return math.floor(norm(a) / (2 ^ n)) end\n  function M.bnot(a) return (TWO32 - 1) - norm(a) end\nend\n\nreturn M\n","lexer":"-- luau-vm/src/lexer.lua\n-- Tokenizer for the Luau subset the VM compiler accepts. Single pass, minimal\n-- allocation (one token table per token, no intermediate substrings beyond the\n-- token text). Returns an array of { type, value, line }.\n\nlocal Lexer = {}\n\nlocal KEYWORDS = {}\nfor _, k in ipairs({\n  'and', 'break', 'do', 'else', 'elseif', 'end', 'false', 'for', 'function',\n  'goto', 'if', 'in', 'local', 'nil', 'not', 'or', 'repeat', 'return', 'then',\n  'true', 'until', 'while',\n}) do KEYWORDS[k] = true end\n\nlocal SYMBOLS = {\n  '...', '..', '::', '==', '~=', '<=', '>=', '//', '<<', '>>',\n  '+', '-', '*', '/', '%', '^', '#', '&', '~', '|', '<', '>', '=',\n  '(', ')', '{', '}', '[', ']', ';', ':', ',', '.',\n}\n\nlocal function isDigit(c) return c >= '0' and c <= '9' end\nlocal function isHex(c)\n  return (c >= '0' and c <= '9') or (c >= 'a' and c <= 'f') or (c >= 'A' and c <= 'F')\nend\nlocal function isAlpha(c)\n  return (c >= 'a' and c <= 'z') or (c >= 'A' and c <= 'Z') or c == '_'\nend\nlocal function isAlphaNum(c) return isAlpha(c) or isDigit(c) end\n\n-- Encode a Unicode code point as UTF-8 (mirrors Lua's luaO_utf8esc: up to 6\n-- bytes for values through 0x7FFFFFFF), so \\u{...} matches native Lua/Luau.\nlocal function utf8esc(cp)\n  if cp < 0x80 then return string.char(cp) end\n  local cont, mfb, x = {}, 0x3f, cp\n  repeat\n    cont[#cont + 1] = 0x80 + (x % 0x40)\n    x = math.floor(x / 0x40)\n    mfb = math.floor(mfb / 2)\n  until x <= mfb\n  local firstByte = ((255 - mfb) * 2) % 256 + x -- (~mfb << 1) | x, byte-wide\n  local out = { string.char(firstByte) }\n  for i = #cont, 1, -1 do out[#out + 1] = string.char(cont[i]) end -- continuation bytes, highlow\n  return table.concat(out)\nend\n\nfunction Lexer.tokenize(src, chunk)\n  chunk = chunk or 'input'\n  local tokens = {}\n  local pos, line, n = 1, 1, #src\n\n  local function err(msg) error(chunk .. ':' .. line .. ': ' .. msg, 0) end\n  local function peek(o) return src:sub(pos + (o or 0), pos + (o or 0)) end\n\n  local function newline()\n    local c = peek(); pos = pos + 1\n    local c2 = peek()\n    if (c2 == '\\n' or c2 == '\\r') and c2 ~= c then pos = pos + 1 end\n    line = line + 1\n  end\n\n  local function readLong()\n    if peek() ~= '[' then return nil end\n    local level, p = 0, pos + 1\n    while src:sub(p, p) == '=' do level = level + 1; p = p + 1 end\n    if src:sub(p, p) ~= '[' then return nil end\n    pos = p + 1\n    if peek() == '\\r' or peek() == '\\n' then newline() end\n    local buf, close = {}, ']' .. string.rep('=', level) .. ']'\n    while true do\n      if pos > n then err('unfinished long bracket') end\n      local c = peek()\n      if c == ']' and src:sub(pos, pos + #close - 1) == close then\n        pos = pos + #close; return table.concat(buf)\n      elseif c == '\\n' or c == '\\r' then buf[#buf + 1] = '\\n'; newline()\n      else buf[#buf + 1] = c; pos = pos + 1 end\n    end\n  end\n\n  local function readString(q)\n    pos = pos + 1\n    local buf = {}\n    while true do\n      if pos > n then err('unfinished string') end\n      local c = peek()\n      if c == q then pos = pos + 1; break\n      elseif c == '\\n' or c == '\\r' then err('unfinished string')\n      elseif c == '\\\\' then\n        pos = pos + 1\n        local e = peek()\n        if e == 'n' then buf[#buf + 1] = '\\n'; pos = pos + 1\n        elseif e == 't' then buf[#buf + 1] = '\\t'; pos = pos + 1\n        elseif e == 'r' then buf[#buf + 1] = '\\r'; pos = pos + 1\n        elseif e == 'a' then buf[#buf + 1] = '\\a'; pos = pos + 1\n        elseif e == 'b' then buf[#buf + 1] = '\\b'; pos = pos + 1\n        elseif e == 'f' then buf[#buf + 1] = '\\f'; pos = pos + 1\n        elseif e == 'v' then buf[#buf + 1] = '\\v'; pos = pos + 1\n        elseif e == '\\\\' then buf[#buf + 1] = '\\\\'; pos = pos + 1\n        elseif e == '\"' then buf[#buf + 1] = '\"'; pos = pos + 1\n        elseif e == \"'\" then buf[#buf + 1] = \"'\"; pos = pos + 1\n        elseif e == '\\n' or e == '\\r' then buf[#buf + 1] = '\\n'; newline()\n        elseif e == 'x' then\n          pos = pos + 1\n          local h = ''\n          for _ = 1, 2 do if isHex(peek()) then h = h .. peek(); pos = pos + 1 end end\n          if #h == 0 then err('hexadecimal digit expected') end\n          buf[#buf + 1] = string.char(tonumber(h, 16))\n        elseif e == 'z' then\n          pos = pos + 1\n          while pos <= n do\n            local w = peek()\n            if w == '\\n' or w == '\\r' then newline()\n            elseif w == ' ' or w == '\\t' or w == '\\f' or w == '\\v' then pos = pos + 1\n            else break end\n          end\n        elseif e == 'u' then\n          -- \\u{XXXX}: Unicode code point, UTF-8 encoded (Lua 5.3+/Luau)\n          pos = pos + 1\n          if peek() ~= '{' then err(\"missing '{' in \\\\u{XXXX}\") end\n          pos = pos + 1\n          local h = ''\n          while isHex(peek()) do h = h .. peek(); pos = pos + 1 end\n          if #h == 0 then err('hexadecimal digit expected') end\n          if peek() ~= '}' then err(\"missing '}' in \\\\u{XXXX}\") end\n          pos = pos + 1\n          local cp = tonumber(h, 16)\n          if cp > 0x7FFFFFFF then err('UTF-8 value too large') end\n          buf[#buf + 1] = utf8esc(cp)\n        elseif isDigit(e) then\n          local d = ''\n          for _ = 1, 3 do if isDigit(peek()) then d = d .. peek(); pos = pos + 1 else break end end\n          local num = tonumber(d)\n          if num > 255 then err('decimal escape too large') end\n          buf[#buf + 1] = string.char(num)\n        else err(\"invalid escape sequence '\\\\\" .. e .. \"'\") end\n      else buf[#buf + 1] = c; pos = pos + 1 end\n    end\n    return table.concat(buf)\n  end\n\n  local function readNumber()\n    local start = pos\n    if peek() == '0' and (peek(1) == 'x' or peek(1) == 'X') then\n      pos = pos + 2\n      while isHex(peek()) or peek() == '.' do pos = pos + 1 end\n      if peek() == 'p' or peek() == 'P' then\n        pos = pos + 1\n        if peek() == '+' or peek() == '-' then pos = pos + 1 end\n        while isDigit(peek()) do pos = pos + 1 end\n      end\n    else\n      while isDigit(peek()) or peek() == '.' do pos = pos + 1 end\n      if peek() == 'e' or peek() == 'E' then\n        pos = pos + 1\n        if peek() == '+' or peek() == '-' then pos = pos + 1 end\n        while isDigit(peek()) do pos = pos + 1 end\n      end\n    end\n    return src:sub(start, pos - 1)\n  end\n\n  while pos <= n do\n    local c = peek()\n    local tokStart = pos\n    if c == '\\n' or c == '\\r' then newline()\n    elseif c == ' ' or c == '\\t' or c == '\\f' or c == '\\v' then pos = pos + 1\n    elseif c == '-' and peek(1) == '-' then\n      pos = pos + 2\n      if peek() == '[' then\n        local saved = pos\n        if readLong() == nil then\n          pos = saved\n          while pos <= n and peek() ~= '\\n' and peek() ~= '\\r' do pos = pos + 1 end\n        end\n      else\n        while pos <= n and peek() ~= '\\n' and peek() ~= '\\r' do pos = pos + 1 end\n      end\n    elseif isAlpha(c) then\n      while isAlphaNum(peek()) do pos = pos + 1 end\n      local w = src:sub(tokStart, pos - 1)\n      tokens[#tokens + 1] = { type = KEYWORDS[w] and 'keyword' or 'name', value = w, line = line }\n    elseif isDigit(c) or (c == '.' and isDigit(peek(1))) then\n      local ln = line\n      tokens[#tokens + 1] = { type = 'number', value = readNumber(), line = ln }\n    elseif c == '\"' or c == \"'\" then\n      local ln = line\n      tokens[#tokens + 1] = { type = 'string', value = readString(c), line = ln }\n    elseif c == '[' and (peek(1) == '[' or peek(1) == '=') then\n      local ln = line\n      local s = readLong()\n      if s ~= nil then tokens[#tokens + 1] = { type = 'string', value = s, line = ln }\n      else tokens[#tokens + 1] = { type = 'symbol', value = '[', line = ln }; pos = pos + 1 end\n    else\n      local matched\n      for _, sym in ipairs(SYMBOLS) do\n        if src:sub(pos, pos + #sym - 1) == sym then matched = sym; break end\n      end\n      if not matched then err(\"unexpected symbol near '\" .. c .. \"'\") end\n      tokens[#tokens + 1] = { type = 'symbol', value = matched, line = line }\n      pos = pos + #matched\n    end\n  end\n  tokens[#tokens + 1] = { type = 'eof', value = '<eof>', line = line }\n  return tokens\nend\n\nreturn Lexer\n","parser":"-- luau-vm/src/parser.lua\n-- Recursive-descent parser with precedence climbing. Produces an AST of tables\n-- tagged with `k`. Covers the executable Luau grammar the compiler lowers.\n\nlocal Lexer = require('lexer')\n\nlocal Parser = {}\nParser.__index = Parser\n\nlocal BLOCK_END = { ['end'] = true, ['else'] = true, ['elseif'] = true, ['until'] = true }\n-- binary op [left, right] priorities; right < left => right associative\nlocal BINPRI = {\n  ['or'] = { 1, 1 }, ['and'] = { 2, 2 },\n  ['<'] = { 3, 3 }, ['>'] = { 3, 3 }, ['<='] = { 3, 3 }, ['>='] = { 3, 3 }, ['~='] = { 3, 3 }, ['=='] = { 3, 3 },\n  ['|'] = { 4, 4 }, ['~'] = { 5, 5 }, ['&'] = { 6, 6 }, ['<<'] = { 7, 7 }, ['>>'] = { 7, 7 },\n  ['..'] = { 9, 8 }, ['+'] = { 10, 10 }, ['-'] = { 10, 10 },\n  ['*'] = { 11, 11 }, ['/'] = { 11, 11 }, ['//'] = { 11, 11 }, ['%'] = { 11, 11 },\n  ['^'] = { 14, 13 },\n}\nlocal UNARY_PRI = 12\n\nlocal function new(tokens, chunk)\n  return setmetatable({ toks = tokens, i = 1, chunk = chunk or 'input' }, Parser)\nend\n\nfunction Parser:peek(o) return self.toks[self.i + (o or 0)] or self.toks[#self.toks] end\nfunction Parser:next() local t = self:peek(); self.i = self.i + 1; return t end\nfunction Parser:err(msg)\n  local t = self:peek()\n  error(self.chunk .. ':' .. t.line .. ': ' .. msg .. \" near '\" .. tostring(t.value) .. \"'\", 0)\nend\nfunction Parser:is(ty, v) local t = self:peek(); return t.type == ty and (v == nil or t.value == v) end\nfunction Parser:isSym(v) return self:is('symbol', v) end\nfunction Parser:isKw(v) return self:is('keyword', v) end\nfunction Parser:accept(ty, v) if self:is(ty, v) then return self:next() end end\nfunction Parser:expect(ty, v) if not self:is(ty, v) then self:err(\"'\" .. tostring(v or ty) .. \"' expected\") end return self:next() end\nfunction Parser:name() if not self:is('name') then self:err('name expected') end return self:next().value end\n\nfunction Parser:parse()\n  local body = self:block()\n  if not self:is('eof') then self:err(\"'<eof>' expected\") end\n  return { k = 'Chunk', body = body }\nend\n\nfunction Parser:block()\n  local stmts = {}\n  while true do\n    local t = self:peek()\n    if t.type == 'eof' then break end\n    if t.type == 'keyword' and BLOCK_END[t.value] then break end\n    if t.type == 'keyword' and t.value == 'return' then stmts[#stmts + 1] = self:retStat(); break end\n    local s = self:statement()\n    if s then stmts[#stmts + 1] = s end\n  end\n  return stmts\nend\n\nfunction Parser:retStat()\n  local line = self:next().line\n  local exprs = {}\n  local t = self:peek()\n  local ends = t.type == 'eof' or (t.type == 'keyword' and BLOCK_END[t.value])\n  if not ends and not self:isSym(';') then exprs = self:exprList() end\n  self:accept('symbol', ';')\n  return { k = 'Return', exprs = exprs, line = line }\nend\n\nfunction Parser:statement()\n  local t = self:peek()\n  if t.type == 'symbol' and t.value == ';' then self:next(); return nil end\n  if t.type == 'symbol' and t.value == '::' then\n    self:next(); local nm = self:name(); self:expect('symbol', '::')\n    return { k = 'Label', name = nm, line = t.line }\n  end\n  if t.type == 'keyword' then\n    local v = t.value\n    if v == 'break' then self:next(); return { k = 'Break', line = t.line } end\n    if v == 'goto' then self:next(); return { k = 'Goto', label = self:name(), line = t.line } end\n    if v == 'do' then self:next(); local b = self:block(); self:expect('keyword', 'end'); return { k = 'Do', body = b, line = t.line } end\n    if v == 'while' then return self:whileStat() end\n    if v == 'repeat' then return self:repeatStat() end\n    if v == 'if' then return self:ifStat() end\n    if v == 'for' then return self:forStat() end\n    if v == 'function' then return self:funcStat() end\n    if v == 'local' then return self:localStat() end\n  end\n  return self:exprStat()\nend\n\nfunction Parser:whileStat()\n  local line = self:next().line\n  local cond = self:expr(); self:expect('keyword', 'do')\n  local body = self:block(); self:expect('keyword', 'end')\n  return { k = 'While', cond = cond, body = body, line = line }\nend\n\nfunction Parser:repeatStat()\n  local line = self:next().line\n  local body = self:block(); self:expect('keyword', 'until')\n  local cond = self:expr()\n  return { k = 'Repeat', body = body, cond = cond, line = line }\nend\n\nfunction Parser:ifStat()\n  local line = self:next().line\n  local clauses = {}\n  local cond = self:expr(); self:expect('keyword', 'then')\n  clauses[1] = { cond = cond, body = self:block() }\n  while self:isKw('elseif') do\n    self:next(); local c = self:expr(); self:expect('keyword', 'then')\n    clauses[#clauses + 1] = { cond = c, body = self:block() }\n  end\n  local elseBody\n  if self:accept('keyword', 'else') then elseBody = self:block() end\n  self:expect('keyword', 'end')\n  return { k = 'If', clauses = clauses, elseBody = elseBody, line = line }\nend\n\nfunction Parser:forStat()\n  local line = self:next().line\n  local first = self:name()\n  if self:isSym('=') then\n    self:next()\n    local a = self:expr(); self:expect('symbol', ','); local b = self:expr()\n    local c\n    if self:accept('symbol', ',') then c = self:expr() end\n    self:expect('keyword', 'do'); local body = self:block(); self:expect('keyword', 'end')\n    return { k = 'NumFor', var = first, start = a, stop = b, step = c, body = body, line = line }\n  end\n  local names = { first }\n  while self:accept('symbol', ',') do names[#names + 1] = self:name() end\n  self:expect('keyword', 'in')\n  local exprs = self:exprList()\n  self:expect('keyword', 'do'); local body = self:block(); self:expect('keyword', 'end')\n  return { k = 'GenFor', names = names, exprs = exprs, body = body, line = line }\nend\n\nfunction Parser:funcStat()\n  local line = self:next().line\n  local base = self:name()\n  local path = {}\n  local method\n  while self:isSym('.') do self:next(); path[#path + 1] = self:name() end\n  if self:accept('symbol', ':') then method = self:name() end\n  local func = self:funcBody(line, method ~= nil)\n  return { k = 'FuncDecl', base = base, path = path, method = method, func = func, line = line }\nend\n\nfunction Parser:localStat()\n  local line = self:next().line\n  if self:accept('keyword', 'function') then\n    local nm = self:name()\n    local func = self:funcBody(line, false)\n    return { k = 'LocalFunc', name = nm, func = func, line = line }\n  end\n  local names = { self:localName() }\n  while self:accept('symbol', ',') do names[#names + 1] = self:localName() end\n  local exprs = {}\n  if self:accept('symbol', '=') then exprs = self:exprList() end\n  return { k = 'Local', names = names, exprs = exprs, line = line }\nend\n\nfunction Parser:localName()\n  local nm = self:name()\n  if self:accept('symbol', '<') then self:name(); self:expect('symbol', '>') end -- attribute, ignored\n  return nm\nend\n\nfunction Parser:funcBody(line, isMethod)\n  self:expect('symbol', '(')\n  local params, isVararg = {}, false\n  if isMethod then params[1] = 'self' end\n  if not self:isSym(')') then\n    repeat\n      if self:isSym('...') then self:next(); isVararg = true; break end\n      params[#params + 1] = self:name()\n    until not self:accept('symbol', ',')\n  end\n  self:expect('symbol', ')')\n  local body = self:block(); self:expect('keyword', 'end')\n  return { k = 'Function', params = params, isVararg = isVararg, body = body, line = line }\nend\n\nfunction Parser:exprStat()\n  local line = self:peek().line\n  local first = self:suffixed()\n  if self:isSym('=') or self:isSym(',') then\n    local targets = { first }\n    while self:accept('symbol', ',') do targets[#targets + 1] = self:suffixed() end\n    self:expect('symbol', '=')\n    local exprs = self:exprList()\n    for _, tg in ipairs(targets) do\n      if tg.k ~= 'Name' and tg.k ~= 'Index' and tg.k ~= 'Field' then self:err('cannot assign') end\n    end\n    return { k = 'Assign', targets = targets, exprs = exprs, line = line }\n  end\n  if first.k ~= 'CallE' and first.k ~= 'Method' then self:err('syntax error') end\n  return { k = 'CallStat', call = first, line = line }\nend\n\nfunction Parser:exprList()\n  local list = { self:expr() }\n  while self:accept('symbol', ',') do list[#list + 1] = self:expr() end\n  return list\nend\n\nfunction Parser:expr() return self:subExpr(0) end\n\nfunction Parser:getBinop()\n  local t = self:peek()\n  if t.type == 'symbol' and BINPRI[t.value] then return t.value end\n  if t.type == 'keyword' and (t.value == 'and' or t.value == 'or') then return t.value end\nend\nfunction Parser:getUnop()\n  local t = self:peek()\n  if t.type == 'symbol' and (t.value == '-' or t.value == '#' or t.value == '~') then return t.value end\n  if t.type == 'keyword' and t.value == 'not' then return t.value end\nend\n\nfunction Parser:subExpr(limit)\n  local e\n  local u = self:getUnop()\n  if u then\n    local line = self:next().line\n    e = { k = 'Unop', op = u, operand = self:subExpr(UNARY_PRI), line = line }\n  else\n    e = self:simple()\n  end\n  while true do\n    local op = self:getBinop()\n    if not op or BINPRI[op][1] <= limit then break end\n    local line = self:next().line\n    local right = self:subExpr(BINPRI[op][2])\n    e = { k = 'Binop', op = op, left = e, right = right, line = line }\n  end\n  return e\nend\n\nfunction Parser:simple()\n  local t = self:peek()\n  if t.type == 'number' then self:next(); return { k = 'Number', value = t.value, line = t.line } end\n  if t.type == 'string' then self:next(); return { k = 'String', value = t.value, line = t.line } end\n  if t.type == 'keyword' then\n    if t.value == 'nil' then self:next(); return { k = 'Nil', line = t.line } end\n    if t.value == 'true' then self:next(); return { k = 'True', line = t.line } end\n    if t.value == 'false' then self:next(); return { k = 'False', line = t.line } end\n    if t.value == 'function' then local l = self:next().line; return self:funcBody(l, false) end\n  end\n  if t.type == 'symbol' then\n    if t.value == '...' then self:next(); return { k = 'Vararg', line = t.line } end\n    if t.value == '{' then return self:table() end\n  end\n  return self:suffixed()\nend\n\nfunction Parser:primary()\n  local t = self:peek()\n  if t.type == 'symbol' and t.value == '(' then\n    self:next(); local e = self:expr(); self:expect('symbol', ')')\n    return { k = 'Paren', expr = e, line = t.line }\n  end\n  if t.type == 'name' then self:next(); return { k = 'Name', name = t.value, line = t.line } end\n  self:err('unexpected symbol')\nend\n\nfunction Parser:suffixed()\n  local e = self:primary()\n  while true do\n    local t = self:peek()\n    if t.type == 'symbol' and t.value == '.' then\n      self:next(); e = { k = 'Field', obj = e, name = self:name(), line = t.line }\n    elseif t.type == 'symbol' and t.value == '[' then\n      self:next(); local idx = self:expr(); self:expect('symbol', ']')\n      e = { k = 'Index', obj = e, index = idx, line = t.line }\n    elseif t.type == 'symbol' and t.value == ':' then\n      self:next(); local m = self:name(); local args = self:callArgs()\n      e = { k = 'Method', obj = e, method = m, args = args, line = t.line }\n    elseif (t.type == 'symbol' and (t.value == '(' or t.value == '{')) or t.type == 'string' then\n      e = { k = 'CallE', func = e, args = self:callArgs(), line = t.line }\n    else break end\n  end\n  return e\nend\n\nfunction Parser:callArgs()\n  local t = self:peek()\n  if t.type == 'string' then self:next(); return { { k = 'String', value = t.value, line = t.line } } end\n  if t.type == 'symbol' and t.value == '{' then return { self:table() } end\n  self:expect('symbol', '(')\n  local args = {}\n  if not self:isSym(')') then args = self:exprList() end\n  self:expect('symbol', ')')\n  return args\nend\n\nfunction Parser:table()\n  local line = self:expect('symbol', '{').line\n  local fields = {}\n  while not self:isSym('}') do\n    if self:isSym('[') then\n      self:next(); local key = self:expr(); self:expect('symbol', ']'); self:expect('symbol', '=')\n      fields[#fields + 1] = { kind = 'keyed', key = key, value = self:expr() }\n    elseif self:is('name') and self:peek(1).type == 'symbol' and self:peek(1).value == '=' then\n      local key = self:next().value; self:next()\n      fields[#fields + 1] = { kind = 'named', key = key, value = self:expr() }\n    else\n      fields[#fields + 1] = { kind = 'item', value = self:expr() }\n    end\n    if not self:accept('symbol', ',') and not self:accept('symbol', ';') then break end\n  end\n  self:expect('symbol', '}')\n  return { k = 'Table', fields = fields, line = line }\nend\n\nfunction Parser.parseString(src, chunk)\n  return new(Lexer.tokenize(src, chunk), chunk):parse()\nend\n\nreturn Parser\n","scope":"-- luau-vm/src/scope.lua\n-- Capture analysis. Resolves every Name to its declaration and marks a\n-- declaration `captured` when it is referenced from a nested function. The\n-- compiler uses `captured` to decide whether a local lives in a cell (box) so\n-- closures can share it as an upvalue.\n--\n-- Declaration objects are attached to the AST and reused by the compiler, which\n-- fills in `owner`/`reg` during code generation.\n\nlocal Scope = {}\n\nlocal function newScope(parent, fdepth) return { vars = {}, parent = parent, fdepth = fdepth } end\nlocal function declare(scope, name)\n  local d = { name = name, captured = false, fdepth = scope.fdepth }\n  scope.vars[name] = d\n  return d\nend\nlocal function lookup(scope, name)\n  local s = scope\n  while s do local d = s.vars[name]; if d then return d end; s = s.parent end\n  return nil\nend\n\nlocal rExpr, rStmt, rBlock, rFunc\n\nfunction Scope.analyze(chunk)\n  local top = newScope(nil, 0)\n  for _, s in ipairs(chunk.body) do rStmt(s, top) end\n  return chunk\nend\n\nfunction rBlock(stmts, parent)\n  local scope = newScope(parent, parent.fdepth)\n  for _, s in ipairs(stmts) do rStmt(s, scope) end\nend\n\nfunction rFunc(fn, parent)\n  local scope = newScope(parent, parent.fdepth + 1)\n  fn.paramDecls = {}\n  for i, p in ipairs(fn.params) do fn.paramDecls[i] = declare(scope, p) end\n  for _, s in ipairs(fn.body) do rStmt(s, scope) end\nend\n\nlocal function ref(node, scope)\n  local d = lookup(scope, node.name)\n  if d then\n    node.decl = d\n    if d.fdepth ~= scope.fdepth then d.captured = true end\n  else\n    node.decl = nil -- global\n  end\nend\n\nfunction rExpr(e, scope)\n  local k = e.k\n  if k == 'Name' then ref(e, scope)\n  elseif k == 'Paren' then rExpr(e.expr, scope)\n  elseif k == 'Field' then rExpr(e.obj, scope)\n  elseif k == 'Index' then rExpr(e.obj, scope); rExpr(e.index, scope)\n  elseif k == 'CallE' then rExpr(e.func, scope); for _, a in ipairs(e.args) do rExpr(a, scope) end\n  elseif k == 'Method' then rExpr(e.obj, scope); for _, a in ipairs(e.args) do rExpr(a, scope) end\n  elseif k == 'Binop' then rExpr(e.left, scope); rExpr(e.right, scope)\n  elseif k == 'Unop' then rExpr(e.operand, scope)\n  elseif k == 'Function' then rFunc(e, scope)\n  elseif k == 'Table' then\n    for _, f in ipairs(e.fields) do\n      if f.kind == 'keyed' then rExpr(f.key, scope) end\n      rExpr(f.value, scope)\n    end\n  end\nend\n\nfunction rStmt(s, scope)\n  local k = s.k\n  if k == 'Local' then\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n    s.decls = {}\n    for i, nm in ipairs(s.names) do s.decls[i] = declare(scope, nm) end\n  elseif k == 'Assign' then\n    for _, t in ipairs(s.targets) do rExpr(t, scope) end\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n  elseif k == 'CallStat' then rExpr(s.call, scope)\n  elseif k == 'Do' then rBlock(s.body, scope)\n  elseif k == 'While' then rExpr(s.cond, scope); rBlock(s.body, scope)\n  elseif k == 'Repeat' then\n    local inner = newScope(scope, scope.fdepth)\n    for _, st in ipairs(s.body) do rStmt(st, inner) end\n    rExpr(s.cond, inner)\n  elseif k == 'If' then\n    for _, c in ipairs(s.clauses) do rExpr(c.cond, scope); rBlock(c.body, scope) end\n    if s.elseBody then rBlock(s.elseBody, scope) end\n  elseif k == 'NumFor' then\n    rExpr(s.start, scope); rExpr(s.stop, scope); if s.step then rExpr(s.step, scope) end\n    local inner = newScope(scope, scope.fdepth)\n    s.varDecl = declare(inner, s.var)\n    for _, st in ipairs(s.body) do rStmt(st, inner) end\n  elseif k == 'GenFor' then\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n    local inner = newScope(scope, scope.fdepth)\n    s.decls = {}\n    for i, nm in ipairs(s.names) do s.decls[i] = declare(inner, nm) end\n    for _, st in ipairs(s.body) do rStmt(st, inner) end\n  elseif k == 'FuncDecl' then\n    -- base is a reference (assignment target); resolve it\n    local nameNode = { k = 'Name', name = s.base, line = s.line }\n    ref(nameNode, scope)\n    s.baseDecl = nameNode.decl\n    rFunc(s.func, scope)\n  elseif k == 'LocalFunc' then\n    s.decl = declare(scope, s.name) -- visible in its own body (recursion)\n    rFunc(s.func, scope)\n  elseif k == 'Return' then\n    for _, e in ipairs(s.exprs) do rExpr(e, scope) end\n  end\n  -- Break / Goto / Label: nothing\nend\n\nreturn Scope\n","optimizer":"-- luau-vm/src/optimizer.lua\n-- AST + bytecode optimization passes. Every pass is semantics-preserving AND\n-- runtime-neutral: we only fold operations whose result has the same observable\n-- value/representation on Lua 5.4 and Luau. Notably `/` and `^` are NOT folded\n-- (they float on 5.4 but Luau prints them without `.0`), and bitwise/comparison\n-- folds are skipped for the same reason.\n\nlocal Opcodes = require('opcodes')\nlocal Op = Opcodes.Op\n\nlocal Optimizer = {}\n\n--  AST: constant folding + dead-code elimination \nlocal function isIntLit(e)\n  if e.k ~= 'Number' then return nil end\n  local v = tonumber(e.value)\n  if v == nil then return nil end\n  if v ~= math.floor(v) then return nil end\n  if e.value:find('[%.eExXpP]') then return nil end -- keep hex/float text as-is\n  return v\nend\n\nlocal FOLD = {\n  ['+'] = function(a, b) return a + b end,\n  ['-'] = function(a, b) return a - b end,\n  ['*'] = function(a, b) return a * b end,\n}\n\nlocal foldExpr\n\nlocal function foldChildren(e)\n  if e.left then e.left = foldExpr(e.left) end\n  if e.right then e.right = foldExpr(e.right) end\n  if e.operand then e.operand = foldExpr(e.operand) end\n  if e.obj then e.obj = foldExpr(e.obj) end\n  if e.index then e.index = foldExpr(e.index) end\n  if e.expr then e.expr = foldExpr(e.expr) end\n  if e.func then e.func = foldExpr(e.func) end\n  if e.args then for i, a in ipairs(e.args) do e.args[i] = foldExpr(a) end end\n  if e.fields then\n    for _, f in ipairs(e.fields) do\n      if f.key and type(f.key) == 'table' then f.key = foldExpr(f.key) end\n      f.value = foldExpr(f.value)\n    end\n  end\n  if e.body then Optimizer.foldBlock(e.body) end\n  return e\nend\n\nfoldExpr = function(e)\n  foldChildren(e)\n  if e.k == 'Binop' then\n    local la, lb = isIntLit(e.left), isIntLit(e.right)\n    if la ~= nil and lb ~= nil and FOLD[e.op] then\n      local v = FOLD[e.op](la, lb)\n      return { k = 'Number', value = tostring(v), line = e.line }\n    end\n    -- literal concat of strings/ints is representation-stable\n    if e.op == '..' then\n      local function litStr(n)\n        if n.k == 'String' then return n.value end\n        if n.k == 'Number' then local iv = isIntLit(n); if iv ~= nil then return tostring(iv) end end\n        return nil\n      end\n      local a, b = litStr(e.left), litStr(e.right)\n      if a ~= nil and b ~= nil then return { k = 'String', value = a .. b, line = e.line } end\n    end\n  elseif e.k == 'Unop' and e.op == '-' then\n    local v = isIntLit(e.operand)\n    if v ~= nil then return { k = 'Number', value = tostring(-v), line = e.line } end\n  end\n  return e\nend\n\nfunction Optimizer.foldBlock(stmts)\n  local cut = nil\n  for i, s in ipairs(stmts) do\n    -- fold expressions inside the statement\n    if s.exprs then for j, e in ipairs(s.exprs) do s.exprs[j] = foldExpr(e) end end\n    if s.targets then for j, e in ipairs(s.targets) do s.targets[j] = foldExpr(e) end end\n    if s.cond then s.cond = foldExpr(s.cond) end\n    if s.call then s.call = foldExpr(s.call) end\n    if s.start then s.start = foldExpr(s.start) end\n    if s.stop then s.stop = foldExpr(s.stop) end\n    if s.step then s.step = foldExpr(s.step) end\n    if s.value then s.value = foldExpr(s.value) end\n    if s.func then foldExpr(s.func) end\n    if s.body then Optimizer.foldBlock(s.body) end\n    if s.elseBody then Optimizer.foldBlock(s.elseBody) end\n    if s.clauses then\n      for _, c in ipairs(s.clauses) do c.cond = foldExpr(c.cond); Optimizer.foldBlock(c.body) end\n    end\n    -- dead-code elimination: statements after an unconditional exit are removed\n    if (s.k == 'Return' or s.k == 'Break') and cut == nil then cut = i end\n  end\n  if cut then for i = #stmts, cut + 1, -1 do stmts[i] = nil end end\nend\n\nfunction Optimizer.optimizeAST(chunk)\n  Optimizer.foldBlock(chunk.body)\n  return chunk\nend\n\n--  bytecode peephole \n-- Only these opcodes use sbx as a relative jump offset (LOADINT's sbx is an\n-- immediate value and must never be retargeted).\nlocal JUMP = {\n  [Op.JMP] = true, [Op.JMPIF] = true, [Op.JMPIFNOT] = true,\n  [Op.FORPREP] = true, [Op.FORLOOP] = true, [Op.TFORLOOP] = true,\n}\n\nlocal function isDroppable(ins)\n  return (ins.op == Op.NOP) or (ins.op == Op.MOVE and ins.a == ins.b)\nend\n\n-- Remove NOPs and self-moves, remapping jump targets so control flow is kept.\nfunction Optimizer.peephole(proto)\n  for _, child in ipairs(proto.protos) do Optimizer.peephole(child) end\n  local code = proto.code\n  -- capture absolute jump targets before removal\n  local absTarget = {}\n  for i, ins in ipairs(code) do\n    if JUMP[ins.op] then absTarget[i] = i + 1 + ins.sbx end\n  end\n  -- map every old index (1..#code+1) to the new index it lands on\n  local newOf, kept, keepOldIndex = {}, {}, {}\n  for i, ins in ipairs(code) do\n    if isDroppable(ins) then\n      newOf[i] = #kept + 1 -- redirect to the next kept instruction\n    else\n      kept[#kept + 1] = ins\n      keepOldIndex[#kept] = i\n      newOf[i] = #kept\n    end\n  end\n  newOf[#code + 1] = #kept + 1\n  -- recompute sbx for kept jumps\n  for newPc, ins in ipairs(kept) do\n    if JUMP[ins.op] then\n      local oldIdx = keepOldIndex[newPc]\n      local newTarget = newOf[absTarget[oldIdx]]\n      ins.sbx = newTarget - (newPc + 1)\n    end\n  end\n  proto.code = kept\n  return proto\nend\n\nreturn Optimizer\n","compiler":"-- luau-vm/src/compiler.lua\n-- Lowers the AST into register-based bytecode protos.\n--\n-- Register model: a function's locals occupy the low registers; expression\n-- temporaries are allocated above `freereg` and freed by restoring it. Captured\n-- locals (scope.captured) are boxed with NEWCELL and accessed via GETCELL/SETCELL\n-- so closures can share them as upvalues.\n--\n-- Multi-value positions (last of a call-arg / return / local-init / assignment\n-- list) use the count convention from opcodes.lua (0 = \"to top\").\n\nlocal Parser = require('parser')\nlocal Scope = require('scope')\nlocal Opcodes = require('opcodes')\nlocal Op = Opcodes.Op\n\nlocal Compiler = {}\n\nlocal function isMultiExpr(e) return e.k == 'CallE' or e.k == 'Method' or e.k == 'Vararg' end\n\n-- '...' is only valid inside a vararg function (Lua/Luau reject it otherwise).\nlocal function assertVararg(fs, line)\n  if not fs.proto.isVararg then\n    error(\"ferret-vm: cannot use '...' outside a vararg function (line \" .. tostring(line) .. ')')\n  end\nend\n\n--  function state \nlocal FS = {}\nFS.__index = FS\n\nlocal function newFS(parent, isVararg)\n  return setmetatable({\n    parent = parent,\n    proto = { code = {}, consts = {}, protos = {}, upvals = {}, lines = {}, numparams = 0, isVararg = isVararg, maxstack = 2 },\n    freereg = 0,\n    constMap = {},\n    upvalMap = {},   -- decl -> upvalue index\n    loops = {},      -- stack of { breaks = {} }\n    lines = {},\n  }, FS)\nend\n\nfunction FS:emit(ins, line)\n  local code = self.proto.code\n  code[#code + 1] = ins\n  self.proto.lines[#code] = line\n  return #code\nend\nfunction FS:here() return #self.proto.code + 1 end -- index the NEXT emitted instruction will get\nfunction FS:patch(j, target)\n  self.proto.code[j].sbx = target - (j + 1)\nend\nfunction FS:reserve(n)\n  self.freereg = self.freereg + n\n  if self.freereg > self.proto.maxstack then self.proto.maxstack = self.freereg end\nend\n\nfunction FS:const(v)\n  local key = type(v) .. '\\0' .. tostring(v)\n  local idx = self.constMap[key]\n  if idx then return idx end\n  local consts = self.proto.consts\n  consts[#consts + 1] = v\n  idx = #consts\n  self.constMap[key] = idx\n  return idx\nend\n\n-- resolve a decl declared in an enclosing function to an upvalue index here.\nfunction FS:upval(decl)\n  local cached = self.upvalMap[decl]\n  if cached then return cached end\n  local parent = self.parent\n  local desc\n  if decl.owner == parent then\n    desc = { kind = 'reg', index = decl.reg }\n  else\n    desc = { kind = 'up', index = parent:upval(decl) }\n  end\n  local ups = self.proto.upvals\n  ups[#ups + 1] = desc\n  local idx = #ups\n  self.upvalMap[decl] = idx\n  return idx\nend\n\n--  expression compilation \nlocal compileExpr, compileExprInto, compileStmt, compileBlock, compileFunc\n\n-- Return a register holding a non-cell local's value directly, else nil.\nlocal function localReg(fs, node)\n  if node.k == 'Name' and node.decl and node.decl.owner == fs and not node.decl.captured then\n    return node.decl.reg\n  end\n  return nil\nend\n\n-- Compile into a freshly reserved register at the top; return it.\nlocal function exprNext(fs, node)\n  local r = fs.freereg\n  fs:reserve(1)\n  compileExprInto(fs, node, r)\n  return r\nend\n\n-- Register holding node's value: a local reg (no copy) or a fresh temp.\nlocal function exprAny(fs, node)\n  local lr = localReg(fs, node)\n  if lr then return lr end\n  return exprNext(fs, node)\nend\n\n-- Compile a call (CallE/Method). Places results at `base`; nresults=-1 => multi.\nlocal function compileCall(fs, node, base, nresults, line)\n  if node.k == 'Method' then\n    -- SELF: R[base+1]=obj, R[base]=obj[method]\n    local robj = exprAny(fs, node.obj)\n    fs.freereg = base\n    fs:reserve(2)\n    fs:emit({ op = Op.SELF, a = base, b = robj, c = fs:const(node.method) }, line)\n    local argBase = base + 2\n    fs.freereg = argBase\n    local b = fs:explistOpen(node.args, argBase) -- args after self\n    -- total args = self + nargs; adjust B (b is count field for args-after-self)\n    local B\n    if b == 0 then B = 0 else B = (b - 1) + 1 + 1 end -- (nargs) + self + 1\n    fs:emit({ op = Op.CALL, a = base, b = B, c = (nresults == -1) and 0 or (nresults + 1) }, line)\n  else\n    fs.freereg = base\n    local rfn = base\n    fs:reserve(1)\n    compileExprInto(fs, node.func, rfn)\n    local b = fs:explistOpen(node.args, base + 1)\n    fs:emit({ op = Op.CALL, a = base, b = b, c = (nresults == -1) and 0 or (nresults + 1) }, line)\n  end\n  fs.freereg = base + math.max(nresults, 0)\nend\n\n-- Compile a list of exprs into consecutive regs from `base`.\n-- Returns the CALL/RETURN \"count\" field: exact = n+1, or 0 (multi, to top).\nfunction FS:explistOpen(exprs, base)\n  local n = #exprs\n  self.freereg = base\n  if n == 0 then return 1 end\n  for i = 1, n - 1 do\n    local r = base + i - 1\n    self.freereg = r\n    self:reserve(1)\n    compileExprInto(self, exprs[i], r)\n  end\n  local last = exprs[n]\n  local lastReg = base + n - 1\n  if isMultiExpr(last) then\n    self.freereg = lastReg\n    if last.k == 'Vararg' then\n      assertVararg(self, last.line)\n      self:reserve(1)\n      self:emit({ op = Op.VARARG, a = lastReg, b = 0 }, last.line)\n    else\n      compileCall(self, last, lastReg, -1, last.line)\n    end\n    return 0\n  else\n    self.freereg = lastReg\n    self:reserve(1)\n    compileExprInto(self, last, lastReg)\n    return n + 1\n  end\nend\n\n-- Compile `exprs` so EXACTLY `want` values land in base..base+want-1. A trailing\n-- call/vararg is closed to the exact number still needed (so a call returning\n-- fewer values nil-fills the rest, instead of leaving stale registers), and any\n-- shortfall is padded with nil. Used by local-decl and multi-assign, which  unlike\n-- return/call-args  need a fixed value count regardless of what the RHS produces.\nfunction FS:explistExact(exprs, base, want)\n  local n = #exprs\n  self.freereg = base\n  if n == 0 then\n    for i = 0, want - 1 do self:emit({ op = Op.LOADNIL, a = base + i, b = 0 }) end\n  else\n    for i = 1, n - 1 do -- all but the last: one value each (evaluated for effect even if beyond want)\n      local r = base + i - 1\n      self.freereg = r; self:reserve(1)\n      compileExprInto(self, exprs[i], r)\n    end\n    local last = exprs[n]\n    local lastReg = base + n - 1\n    local remaining = want - (n - 1) -- values the last expr must supply\n    if isMultiExpr(last) then\n      local req = remaining >= 1 and remaining or 1 -- evaluate even when discarded (side effects)\n      self.freereg = lastReg; self:reserve(req)\n      if last.k == 'Vararg' then\n        assertVararg(self, last.line)\n        self:emit({ op = Op.VARARG, a = lastReg, b = req + 1 }, last.line)\n      else\n        compileCall(self, last, lastReg, req, last.line)\n      end\n    else\n      self.freereg = lastReg; self:reserve(1)\n      compileExprInto(self, last, lastReg)\n      for i = 1, remaining - 1 do -- want > #exprs: pad the extra targets with nil\n        self:emit({ op = Op.LOADNIL, a = lastReg + i, b = 0 }, last.line)\n      end\n    end\n  end\n  self.freereg = base + want\n  if self.freereg > self.proto.maxstack then self.proto.maxstack = self.freereg end\nend\n\nlocal BINOP = {\n  ['+'] = Op.ADD, ['-'] = Op.SUB, ['*'] = Op.MUL, ['/'] = Op.DIV, ['%'] = Op.MOD,\n  ['^'] = Op.POW, ['//'] = Op.IDIV, ['&'] = Op.BAND, ['|'] = Op.BOR, ['~'] = Op.BXOR,\n  ['<<'] = Op.SHL, ['>>'] = Op.SHR,\n}\n\ncompileExprInto = function(fs, node, target)\n  local k = node.k\n  local line = node.line\n  if k == 'Nil' then fs:emit({ op = Op.LOADNIL, a = target, b = 0 }, line)\n  elseif k == 'True' then fs:emit({ op = Op.LOADBOOL, a = target, b = 1 }, line)\n  elseif k == 'False' then fs:emit({ op = Op.LOADBOOL, a = target, b = 0 }, line)\n  elseif k == 'Number' then\n    local v = tonumber(node.value)\n    -- small integer immediates avoid a constant slot\n    if math.type and math.type(v) == 'integer' and v >= -32768 and v <= 32767 then\n      fs:emit({ op = Op.LOADINT, a = target, sbx = v }, line)\n    elseif not math.type and v == math.floor(v) and v >= -32768 and v <= 32767 then\n      fs:emit({ op = Op.LOADINT, a = target, sbx = v }, line)\n    else\n      fs:emit({ op = Op.LOADK, a = target, bx = fs:const(v) }, line)\n    end\n  elseif k == 'String' then fs:emit({ op = Op.LOADK, a = target, bx = fs:const(node.value) }, line)\n  elseif k == 'Vararg' then assertVararg(fs, line); fs:emit({ op = Op.VARARG, a = target, b = 2 }, line)\n  elseif k == 'Paren' then\n    compileExprInto(fs, node.expr, target) -- single value already\n  elseif k == 'Name' then\n    local d = node.decl\n    if not d then\n      fs:emit({ op = Op.GETGLOBAL, a = target, bx = fs:const(node.name) }, line)\n    elseif d.owner == fs then\n      if d.captured then fs:emit({ op = Op.GETCELL, a = target, b = d.reg }, line)\n      elseif d.reg ~= target then fs:emit({ op = Op.MOVE, a = target, b = d.reg }, line) end\n    else\n      fs:emit({ op = Op.GETUPVAL, a = target, b = fs:upval(d) }, line)\n    end\n  elseif k == 'Field' then\n    local save = fs.freereg\n    local robj = exprAny(fs, node.obj)\n    fs:emit({ op = Op.GETFIELD, a = target, b = robj, bx = fs:const(node.name) }, line)\n    fs.freereg = save\n  elseif k == 'Index' then\n    local save = fs.freereg\n    local robj = exprAny(fs, node.obj)\n    local ridx = exprAny(fs, node.index)\n    fs:emit({ op = Op.GETTABLE, a = target, b = robj, c = ridx }, line)\n    fs.freereg = save\n  elseif k == 'CallE' or k == 'Method' then\n    compileCall(fs, node, target, 1, line)\n  elseif k == 'Function' then\n    compileFunc(fs, node, target)\n  elseif k == 'Table' then\n    compileTable(fs, node, target)\n  elseif k == 'Unop' then\n    local save = fs.freereg\n    local rb = exprAny(fs, node.operand)\n    local opmap = { ['-'] = Op.UNM, ['not'] = Op.NOT, ['#'] = Op.LEN, ['~'] = Op.BNOT }\n    fs:emit({ op = opmap[node.op], a = target, b = rb }, line)\n    fs.freereg = save\n  elseif k == 'Binop' then\n    compileBinop(fs, node, target)\n  else\n    error('compiler: cannot compile expr ' .. tostring(k))\n  end\nend\n\nfunction compileBinop(fs, node, target)\n  local op, line = node.op, node.line\n  if op == 'and' then\n    compileExprInto(fs, node.left, target)\n    local j = fs:emit({ op = Op.JMPIFNOT, a = target, sbx = 0 }, line)\n    compileExprInto(fs, node.right, target)\n    fs:patch(j, fs:here())\n    return\n  elseif op == 'or' then\n    compileExprInto(fs, node.left, target)\n    local j = fs:emit({ op = Op.JMPIF, a = target, sbx = 0 }, line)\n    compileExprInto(fs, node.right, target)\n    fs:patch(j, fs:here())\n    return\n  end\n  local save = fs.freereg\n  if op == '..' then\n    local r1 = exprNext(fs, node.left)\n    local r2 = exprNext(fs, node.right)\n    fs:emit({ op = Op.CONCAT, a = target, b = r1, c = r2 }, line)\n  elseif BINOP[op] then\n    local rb = exprAny(fs, node.left)\n    local rc = exprAny(fs, node.right)\n    fs:emit({ op = BINOP[op], a = target, b = rb, c = rc }, line)\n  elseif op == '==' or op == '~=' then\n    local rb = exprAny(fs, node.left)\n    local rc = exprAny(fs, node.right)\n    fs:emit({ op = Op.EQ, a = target, b = rb, c = rc }, line)\n    if op == '~=' then fs:emit({ op = Op.NOT, a = target, b = target }, line) end\n  elseif op == '<' or op == '>' then\n    local l, r = node.left, node.right\n    if op == '>' then l, r = r, l end\n    local rb = exprAny(fs, l)\n    local rc = exprAny(fs, r)\n    fs:emit({ op = Op.LT, a = target, b = rb, c = rc }, line)\n  elseif op == '<=' or op == '>=' then\n    local l, r = node.left, node.right\n    if op == '>=' then l, r = r, l end\n    local rb = exprAny(fs, l)\n    local rc = exprAny(fs, r)\n    fs:emit({ op = Op.LE, a = target, b = rb, c = rc }, line)\n  else\n    error('compiler: bad binop ' .. tostring(op))\n  end\n  fs.freereg = save\nend\n\nfunction compileTable(fs, node, target)\n  -- Positional (array) values are held in a contiguous block above the table\n  -- register and flushed with one SETLIST at the END, so they win over any\n  -- same-index keyed field (matching Lua's evaluation order). Keyed/named\n  -- fields are stored as encountered, using temporaries above the block.\n  local save = fs.freereg\n  fs:emit({ op = Op.NEWTABLE, a = target }, node.line)\n  local arrayBase = target + 1\n  fs.freereg = arrayBase\n  local arrayCount = 0\n  local multiLast = false\n  local nfields = #node.fields\n  for i, f in ipairs(node.fields) do\n    if f.kind == 'item' then\n      local r = arrayBase + arrayCount\n      fs.freereg = r\n      if i == nfields and isMultiExpr(f.value) then\n        if f.value.k == 'Vararg' then\n          assertVararg(fs, node.line)\n          fs:reserve(1)\n          fs:emit({ op = Op.VARARG, a = r, b = 0 }, node.line)\n        else\n          compileCall(fs, f.value, r, -1, node.line)\n        end\n        multiLast = true\n      else\n        fs:reserve(1)\n        compileExprInto(fs, f.value, r)\n        arrayCount = arrayCount + 1\n      end\n    else\n      local blockTop = arrayBase + arrayCount\n      fs.freereg = blockTop\n      if f.kind == 'named' then\n        local rv = exprNext(fs, f.value)\n        fs:emit({ op = Op.SETFIELD, a = target, bx = fs:const(f.key), c = rv }, node.line)\n      else\n        local rk = exprNext(fs, f.key)\n        local rv = exprNext(fs, f.value)\n        fs:emit({ op = Op.SETTABLE, a = target, b = rk, c = rv }, node.line)\n      end\n      fs.freereg = blockTop -- keep the positional block intact\n    end\n  end\n  if multiLast then\n    fs:emit({ op = Op.SETLIST, a = target, b = 0, c = 0 }, node.line)\n  elseif arrayCount > 0 then\n    fs:emit({ op = Op.SETLIST, a = target, b = arrayCount, c = 0 }, node.line)\n  end\n  fs.freereg = save\nend\n\n--  function bodies \ncompileFunc = function(fs, node, target)\n  local child = newFS(fs, node.isVararg)\n  child.proto.numparams = #node.params\n  -- declare params as locals\n  for i, decl in ipairs(node.paramDecls) do\n    decl.owner = child\n    decl.reg = i - 1\n    child.freereg = math.max(child.freereg, i)\n  end\n  child:reserve(0)\n  if child.proto.numparams > child.proto.maxstack then child.proto.maxstack = child.proto.numparams + 2 end\n  -- box captured params\n  for _, decl in ipairs(node.paramDecls) do\n    if decl.captured then child:emit({ op = Op.NEWCELL, a = decl.reg }, node.line) end\n  end\n  compileBlock(child, node.body)\n  child:emit({ op = Op.RETURN, a = 0, b = 1 }, node.line) -- implicit return\n  local protos = fs.proto.protos\n  protos[#protos + 1] = child.proto\n  fs:emit({ op = Op.CLOSURE, a = target, bx = #protos }, node.line)\nend\n\n--  statements \nfunction compileBlock(fs, stmts)\n  local save = fs.freereg\n  local savedLocals = fs._activeCount or 0\n  for _, s in ipairs(stmts) do compileStmt(fs, s) end\n  fs.freereg = save\nend\n\nlocal function declareLocal(fs, decl, line)\n  local r = fs.freereg\n  fs:reserve(1)\n  decl.owner = fs\n  decl.reg = r\n  return r\nend\n\ncompileStmt = function(fs, s)\n  local k = s.k\n  local line = s.line\n  if k == 'Local' then\n    local base = fs.freereg\n    -- produce exactly #names values (nil-filling short calls / vararg)  see explistExact\n    fs:explistExact(s.exprs, base, #s.names)\n    for i, decl in ipairs(s.decls) do\n      decl.owner = fs\n      decl.reg = base + i - 1\n      if decl.captured then fs:emit({ op = Op.NEWCELL, a = decl.reg }, line) end\n    end\n  elseif k == 'LocalFunc' then\n    local r = declareLocal(fs, s.decl, line)\n    if s.decl.captured then\n      -- reserve cell first so recursion sees it\n      fs:emit({ op = Op.LOADNIL, a = r, b = 0 }, line)\n      fs:emit({ op = Op.NEWCELL, a = r }, line)\n      local tmp = fs.freereg\n      fs:reserve(1)\n      compileFunc(fs, s.func, tmp)\n      fs:emit({ op = Op.SETCELL, a = r, b = tmp }, line)\n      fs.freereg = r + 1\n    else\n      compileFunc(fs, s.func, r)\n    end\n  elseif k == 'Assign' then\n    compileAssign(fs, s)\n  elseif k == 'FuncDecl' then\n    compileFuncDecl(fs, s)\n  elseif k == 'CallStat' then\n    local save = fs.freereg\n    compileCall(fs, s.call, fs.freereg, 0, line)\n    fs.freereg = save\n  elseif k == 'Do' then\n    compileBlock(fs, s.body)\n  elseif k == 'Return' then\n    local base = fs.freereg\n    local count = fs:explistOpen(s.exprs, base)\n    fs:emit({ op = Op.RETURN, a = base, b = count }, line)\n    fs.freereg = base\n  elseif k == 'If' then\n    compileIf(fs, s)\n  elseif k == 'While' then\n    compileWhile(fs, s)\n  elseif k == 'Repeat' then\n    compileRepeat(fs, s)\n  elseif k == 'NumFor' then\n    compileNumFor(fs, s)\n  elseif k == 'GenFor' then\n    compileGenFor(fs, s)\n  elseif k == 'Break' then\n    local loop = fs.loops[#fs.loops]\n    if not loop then error('compiler: break outside loop') end\n    local j = fs:emit({ op = Op.JMP, sbx = 0 }, line)\n    loop.breaks[#loop.breaks + 1] = j\n  elseif k == 'Goto' or k == 'Label' then\n    error('ferret-vm: goto/label is not supported (Luau has no goto)')\n  else\n    error('compiler: cannot compile stmt ' .. tostring(k))\n  end\nend\n\nfunction compileAssign(fs, s)\n  local save = fs.freereg\n  local n = #s.targets\n  if n == 1 and #s.exprs == 1 then\n    compileStore(fs, s.targets[1], s.exprs[1], s.line)\n    fs.freereg = save\n    return\n  end\n  -- evaluate exactly n RHS values into consecutive temps (nil-filling short\n  -- calls / vararg  see explistExact), then store into the targets\n  local base = fs.freereg\n  fs:explistExact(s.exprs, base, n)\n  fs.freereg = base + n\n  for i = 1, n do\n    compileStoreReg(fs, s.targets[i], base + i - 1, s.line)\n  end\n  fs.freereg = save\nend\n\n-- store the value of `valueNode` into target lvalue\nfunction compileStore(fs, target, valueNode, line)\n  if target.k == 'Name' then\n    local d = target.decl\n    if not d then\n      local r = exprNext(fs, valueNode)\n      fs:emit({ op = Op.SETGLOBAL, a = r, bx = fs:const(target.name) }, line)\n    elseif d.owner == fs then\n      if d.captured then\n        local r = exprNext(fs, valueNode)\n        fs:emit({ op = Op.SETCELL, a = d.reg, b = r }, line)\n      else\n        -- Calls/methods/tables use [target+1..] as scratch, which would clobber\n        -- other live locals (and args read from them). Evaluate into a fresh\n        -- temp above the locals, then move into place.\n        local vk = valueNode.k\n        if vk == 'CallE' or vk == 'Method' or vk == 'Table' then\n          local save = fs.freereg\n          local tmp = exprNext(fs, valueNode)\n          if tmp ~= d.reg then fs:emit({ op = Op.MOVE, a = d.reg, b = tmp }, line) end\n          fs.freereg = save\n        else\n          compileExprInto(fs, valueNode, d.reg)\n        end\n      end\n    else\n      local r = exprNext(fs, valueNode)\n      fs:emit({ op = Op.SETUPVAL, a = r, b = fs:upval(d) }, line)\n    end\n  elseif target.k == 'Field' then\n    local robj = exprAny(fs, target.obj)\n    local rv = exprNext(fs, valueNode)\n    fs:emit({ op = Op.SETFIELD, a = robj, bx = fs:const(target.name), c = rv }, line)\n  elseif target.k == 'Index' then\n    local robj = exprAny(fs, target.obj)\n    local rk = exprAny(fs, target.index)\n    local rv = exprNext(fs, valueNode)\n    fs:emit({ op = Op.SETTABLE, a = robj, b = rk, c = rv }, line)\n  end\nend\n\n-- store an already-computed value (in register `vreg`) into target lvalue\nfunction compileStoreReg(fs, target, vreg, line)\n  if target.k == 'Name' then\n    local d = target.decl\n    if not d then fs:emit({ op = Op.SETGLOBAL, a = vreg, bx = fs:const(target.name) }, line)\n    elseif d.owner == fs then\n      if d.captured then fs:emit({ op = Op.SETCELL, a = d.reg, b = vreg }, line)\n      elseif d.reg ~= vreg then fs:emit({ op = Op.MOVE, a = d.reg, b = vreg }, line) end\n    else fs:emit({ op = Op.SETUPVAL, a = vreg, b = fs:upval(d) }, line) end\n  elseif target.k == 'Field' then\n    local robj = exprAny(fs, target.obj)\n    fs:emit({ op = Op.SETFIELD, a = robj, bx = fs:const(target.name), c = vreg }, line)\n  elseif target.k == 'Index' then\n    local robj = exprAny(fs, target.obj)\n    local rk = exprAny(fs, target.index)\n    fs:emit({ op = Op.SETTABLE, a = robj, b = rk, c = vreg }, line)\n  end\nend\n\nfunction compileFuncDecl(fs, s)\n  -- build the target lvalue: base [.path]* [:method]\n  local line = s.line\n  if #s.path == 0 and not s.method then\n    -- assign to base (local/upval/global)\n    local nameNode = { k = 'Name', name = s.base, decl = s.baseDecl, line = line }\n    compileStore(fs, nameNode, s.func, line)\n  else\n    -- resolve base object, then descend fields, set last\n    local save = fs.freereg\n    local baseNode = { k = 'Name', name = s.base, decl = s.baseDecl, line = line }\n    local robj = exprNext(fs, baseNode)\n    for i = 1, #s.path - (s.method and 0 or 1) do\n      local nxt = fs.freereg\n      fs:reserve(1)\n      fs:emit({ op = Op.GETFIELD, a = nxt, b = robj, bx = fs:const(s.path[i]) }, line)\n      robj = nxt\n    end\n    local lastKey = s.method or s.path[#s.path]\n    local rv = exprNext(fs, s.func)\n    fs:emit({ op = Op.SETFIELD, a = robj, bx = fs:const(lastKey), c = rv }, line)\n    fs.freereg = save\n  end\nend\n\n-- if / elseif / else\nfunction compileIf(fs, s)\n  local endJumps = {}\n  for ci, clause in ipairs(s.clauses) do\n    local save = fs.freereg\n    local rc = exprNext(fs, clause.cond)\n    fs.freereg = save\n    local jnext = fs:emit({ op = Op.JMPIFNOT, a = rc, sbx = 0 }, clause.cond.line)\n    compileBlock(fs, clause.body)\n    if s.elseBody or ci < #s.clauses then\n      endJumps[#endJumps + 1] = fs:emit({ op = Op.JMP, sbx = 0 }, s.line)\n    end\n    fs:patch(jnext, fs:here())\n  end\n  if s.elseBody then compileBlock(fs, s.elseBody) end\n  for _, j in ipairs(endJumps) do fs:patch(j, fs:here()) end\nend\n\nfunction compileWhile(fs, s)\n  local top = fs:here()\n  local save = fs.freereg\n  local rc = exprNext(fs, s.cond)\n  fs.freereg = save\n  local jexit = fs:emit({ op = Op.JMPIFNOT, a = rc, sbx = 0 }, s.line)\n  fs.loops[#fs.loops + 1] = { breaks = {} }\n  compileBlock(fs, s.body)\n  local jback = fs:emit({ op = Op.JMP, sbx = 0 }, s.line)\n  fs:patch(jback, top)\n  fs:patch(jexit, fs:here())\n  local loop = table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\nfunction compileRepeat(fs, s)\n  local top = fs:here()\n  fs.loops[#fs.loops + 1] = { breaks = {} }\n  -- body and until share scope; compile inline (no freereg reset before cond)\n  local save = fs.freereg\n  for _, st in ipairs(s.body) do compileStmt(fs, st) end\n  local rc = exprNext(fs, s.cond)\n  local jback = fs:emit({ op = Op.JMPIFNOT, a = rc, sbx = 0 }, s.line)\n  fs:patch(jback, top)\n  fs.freereg = save\n  local loop = table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\nfunction compileNumFor(fs, s)\n  local base = fs.freereg\n  exprNext(fs, s.start)  -- base\n  exprNext(fs, s.stop)   -- base+1\n  if s.step then exprNext(fs, s.step) else\n    fs:emit({ op = Op.LOADINT, a = fs.freereg, sbx = 1 }, s.line); fs:reserve(1)\n  end\n  fs:reserve(1) -- loop var at base+3\n  if fs.freereg > fs.proto.maxstack then fs.proto.maxstack = fs.freereg end\n  s.varDecl.owner = fs\n  s.varDecl.reg = base + 3\n  local jprep = fs:emit({ op = Op.FORPREP, a = base, sbx = 0 }, s.line)\n  fs.loops[#fs.loops + 1] = { breaks = {} }\n  local bodyStart = fs:here()\n  if s.varDecl.captured then fs:emit({ op = Op.NEWCELL, a = base + 3 }, s.line) end\n  compileBlock(fs, s.body)\n  local loopIns = fs:emit({ op = Op.FORLOOP, a = base, sbx = 0 }, s.line)\n  fs:patch(jprep, loopIns)     -- FORPREP jumps forward to the FORLOOP instruction\n  fs:patch(loopIns, bodyStart) -- FORLOOP jumps back to the body start\n  fs.freereg = base\n  local loop = table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\nfunction compileGenFor(fs, s)\n  local base = fs.freereg\n  -- iterator function, state, control (3 values) from exprs\n  local count = fs:explistOpen(s.exprs, base)\n  local have = (count == 0) and 3 or (count - 1)\n  for i = have, 2 do fs:emit({ op = Op.LOADNIL, a = base + i, b = 0 }, s.line) end\n  fs.freereg = base + 3\n  -- loop vars at base+3 ...\n  local nvars = #s.decls\n  fs:reserve(nvars)\n  if fs.freereg > fs.proto.maxstack then fs.proto.maxstack = fs.freereg end\n  for i, decl in ipairs(s.decls) do decl.owner = fs; decl.reg = base + 3 + (i - 1) end\n  local jto = fs:emit({ op = Op.JMP, sbx = 0 }, s.line) -- jump to TFORCALL\n  fs.loops[#fs.loops + 1] = { breaks = {} }\n  local bodyStart = fs:here()\n  for _, decl in ipairs(s.decls) do\n    if decl.captured then fs:emit({ op = Op.NEWCELL, a = decl.reg }, s.line) end\n  end\n  compileBlock(fs, s.body)\n  fs:patch(jto, fs:here())\n  fs:emit({ op = Op.TFORCALL, a = base, c = nvars }, s.line)\n  local jloop = fs:emit({ op = Op.TFORLOOP, a = base, sbx = 0 }, s.line)\n  fs:patch(jloop, bodyStart)\n  fs.freereg = base\n  local loop = table.remove(fs.loops)\n  for _, j in ipairs(loop.breaks) do fs:patch(j, fs:here()) end\nend\n\n--  entry \nfunction Compiler.compileAST(chunk)\n  Scope.analyze(chunk)\n  local main = newFS(nil, true)\n  main.proto.isVararg = true\n  compileBlock(main, chunk.body)\n  main:emit({ op = Op.RETURN, a = 0, b = 1 }, 0)\n  return main.proto\nend\n\nfunction Compiler.compile(src, chunkName, opts)\n  opts = opts or {}\n  local chunk = Parser.parseString(src, chunkName)\n  if opts.optimize ~= false then\n    local Optimizer = require('optimizer')\n    Optimizer.optimizeAST(chunk)\n    local proto = Compiler.compileAST(chunk)\n    Optimizer.peephole(proto)\n    return proto\n  end\n  return Compiler.compileAST(chunk)\nend\n\nreturn Compiler\n","serializer":"-- luau-vm/src/serializer.lua\n-- Compact binary encoding of a compiled proto tree, and its inverse loader.\n-- No loadstring: bytes -> runtime proto tables directly.\n--\n-- Format\n--   magic  'FVM' , version(1 byte)\n--   uint32 checksum (FNV-1a over the body)\n--   uint32 bodyLength\n--   body:  proto (recursive)\n-- Integers use zig-zag LEB128 varints; numbers round-trip via %.17g text so no\n-- string.pack dependency (works on Lua 5.1+/Luau uniformly).\n\nlocal Opcodes = require('opcodes')\nlocal Bit = require('bitops')\n\nlocal Serializer = {}\n\nlocal MAGIC = 'FVM'\nlocal VERSION = 1\n\n--  writer \nlocal function Writer()\n  return { buf = {}, put = function(self, s) self.buf[#self.buf + 1] = s end }\nend\nlocal function writeByte(w, b) w:put(string.char(b % 256)) end\nlocal function writeUVarint(w, x)\n  x = math.floor(x)\n  while true do\n    local b = x % 128\n    x = math.floor(x / 128)\n    if x > 0 then writeByte(w, b + 128) else writeByte(w, b); break end\n  end\nend\nlocal function writeSVarint(w, x)\n  x = math.floor(x)\n  local zz = x >= 0 and (x * 2) or (-x * 2 - 1) -- zig-zag\n  writeUVarint(w, zz)\nend\nlocal function writeString(w, s)\n  writeUVarint(w, #s)\n  w:put(s)\nend\nlocal function writeU32(w, x)\n  x = math.floor(x) % 4294967296\n  for _ = 1, 4 do writeByte(w, x % 256); x = math.floor(x / 256) end\nend\n\n--  reader \nlocal function Reader(s) return { s = s, pos = 1 } end\n-- EOF-safe: a truncated/corrupt stream reports its position instead of faulting\n-- later on a nil (e.g. `nil % 128`). Keeps malformed input from crashing the host.\nlocal function readByte(r)\n  local b = string.byte(r.s, r.pos)\n  if b == nil then error('serializer: unexpected end of bytecode at offset ' .. r.pos) end\n  r.pos = r.pos + 1\n  return b\nend\nlocal function readUVarint(r)\n  local x, shift = 0, 1\n  while true do\n    local b = readByte(r)\n    x = x + (b % 128) * shift\n    if b < 128 then break end\n    shift = shift * 128\n  end\n  return x\nend\nlocal function readSVarint(r)\n  local zz = readUVarint(r)\n  -- math.floor keeps an integer subtype on Lua 5.4 (unlike `/`, which floats)\n  if zz % 2 == 0 then return math.floor(zz / 2) else return -math.floor((zz + 1) / 2) end\nend\nlocal function readString(r)\n  local n = readUVarint(r)\n  local s = r.s:sub(r.pos, r.pos + n - 1)\n  r.pos = r.pos + n\n  return s\nend\nlocal function readU32(r)\n  local x, m = 0, 1\n  for _ = 1, 4 do x = x + readByte(r) * m; m = m * 256 end\n  return x\nend\n\n--  value (constant) encoding \nlocal T_NIL, T_TRUE, T_FALSE, T_INT, T_NUM, T_STR = 0, 1, 2, 3, 4, 5\nlocal function writeValue(w, v)\n  local t = type(v)\n  if v == nil then writeByte(w, T_NIL)\n  elseif v == true then writeByte(w, T_TRUE)\n  elseif v == false then writeByte(w, T_FALSE)\n  elseif t == 'number' then\n    if math.floor(v) == v and v >= -2147483648 and v <= 2147483647 then\n      writeByte(w, T_INT); writeSVarint(w, v)\n    else\n      writeByte(w, T_NUM); writeString(w, string.format('%.17g', v))\n    end\n  elseif t == 'string' then writeByte(w, T_STR); writeString(w, v)\n  else error('serializer: cannot encode constant of type ' .. t) end\nend\nlocal function readValue(r)\n  local t = readByte(r)\n  if t == T_NIL then return nil\n  elseif t == T_TRUE then return true\n  elseif t == T_FALSE then return false\n  elseif t == T_INT then return readSVarint(r)\n  elseif t == T_NUM then return tonumber(readString(r))\n  elseif t == T_STR then return readString(r)\n  else error('serializer: bad constant tag ' .. tostring(t)) end\nend\n\n--  proto encoding \n-- opMap (optional): canonical opcode -> the byte written for it. Lets a build\n-- ship a per-build opcode numbering so the bytecode can't be read by a\n-- devirtualizer keyed to the canonical set. ins.op stays canonical internally,\n-- so operand-layout lookup and the VM's dispatch are unaffected.\nlocal function writeProto(w, p, opMap)\n  writeUVarint(w, p.numparams)\n  writeByte(w, p.isVararg and 1 or 0)\n  writeUVarint(w, p.maxstack)\n  -- upvalues\n  writeUVarint(w, #p.upvals)\n  for _, d in ipairs(p.upvals) do\n    writeByte(w, d.kind == 'reg' and 0 or 1)\n    writeUVarint(w, d.index)\n  end\n  -- constants\n  writeUVarint(w, #p.consts)\n  for _, c in ipairs(p.consts) do writeValue(w, c) end\n  -- code\n  writeUVarint(w, #p.code)\n  for _, ins in ipairs(p.code) do\n    writeByte(w, opMap and opMap[ins.op] or ins.op)\n    for _, field in ipairs(Opcodes.operands[ins.op]) do\n      writeSVarint(w, ins[field] or 0)\n    end\n  end\n  -- nested protos\n  writeUVarint(w, #p.protos)\n  for _, child in ipairs(p.protos) do writeProto(w, child, opMap) end\nend\n\n-- invMap (optional): the inverse of opMap (written byte -> canonical opcode).\nlocal function readProto(r, invMap)\n  local p = { upvals = {}, consts = {}, code = {}, protos = {}, lines = {} }\n  p.numparams = readUVarint(r)\n  p.isVararg = readByte(r) == 1\n  p.maxstack = readUVarint(r)\n  for i = 1, readUVarint(r) do\n    local kind = readByte(r) == 0 and 'reg' or 'up'\n    p.upvals[i] = { kind = kind, index = readUVarint(r) }\n  end\n  for i = 1, readUVarint(r) do p.consts[i] = readValue(r) end\n  local ncode = readUVarint(r)\n  for i = 1, ncode do\n    local op = readByte(r)\n    if invMap then op = invMap[op] end\n    local ins = { op = op }\n    for _, field in ipairs(Opcodes.operands[op]) do ins[field] = readSVarint(r) end\n    p.code[i] = ins\n  end\n  for i = 1, readUVarint(r) do p.protos[i] = readProto(r, invMap) end\n  return p\nend\n\n--  FNV-1a checksum (32-bit, portable) \nlocal function fnv1a(s)\n  local h = 2166136261\n  for i = 1, #s do\n    h = Bit.bxor(h, s:byte(i))\n    -- h * 16777619 mod 2^32, split to stay exact in doubles\n    local lo = (h % 65536) * 16777619\n    local hi = (math.floor(h / 65536) * 16777619) % 65536\n    h = (lo + hi * 65536) % 4294967296\n  end\n  return math.floor(h)\nend\n\n--  public API \nfunction Serializer.serialize(proto, opMap)\n  local w = Writer()\n  writeProto(w, proto, opMap)\n  local body = table.concat(w.buf)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, fnv1a(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nfunction Serializer.deserialize(bytes, invMap)\n  local r = Reader(bytes)\n  if bytes:sub(1, 3) ~= MAGIC then error('serializer: bad magic (not ferret bytecode)') end\n  r.pos = 4\n  local version = readByte(r)\n  if version ~= VERSION then error('serializer: unsupported version ' .. version) end\n  local checksum = readU32(r)\n  local bodyLen = readU32(r)\n  local body = bytes:sub(r.pos, r.pos + bodyLen - 1)\n  if fnv1a(body) ~= checksum then error('serializer: checksum mismatch (corrupt bytecode)') end\n  local br = Reader(body)\n  return readProto(br, invMap)\nend\n\n-- Recompute the container checksum over the current body. Lets tooling (e.g.\n-- the malformed-bytecode fuzzer) craft *well-formed-but-nonsense* bytecode that\n-- passes the checksum, so the structural validator  not the checksum  is what\n-- must catch it. Returns a resealed container the loader will accept.\nfunction Serializer.reseal(bytes)\n  local body = bytes:sub(13) -- MAGIC(3)+VERSION(1)+checksum(4)+bodyLen(4)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, fnv1a(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nSerializer.MAGIC = MAGIC\nSerializer.VERSION = VERSION\nreturn Serializer\n","vm":"-- luau-vm/src/vm.lua\n-- Register-based interpreter for the ferret custom bytecode.\n--\n-- Design choices that buy correctness + Luau compatibility cheaply:\n--   * A VM closure is a REAL Lua function (see makeClosure) that runs `execute`.\n--     So VM and host functions are invoked identically, and metamethods, pcall,\n--     coroutines, table.sort(cmp), etc. all work because a compiled function is\n--     an ordinary callable Lua value.\n--   * All operators use the host's native ops (R[b] + R[c], R[b][k], #x, ..),\n--     so metatables (__index/__add/__concat/__len/) are honored by the host.\n--   * Captured locals & upvalues are \"cells\" ({v=...}); closures capture cell\n--     references, so no open/closed-upvalue bookkeeping is needed.\n--\n-- table.pack/unpack carry multiple values across call boundaries, so multiple\n-- returns and varargs are exact.\n\nlocal Opcodes = require('opcodes')\nlocal Bit = require('bitops')\nlocal Op = Opcodes.Op\n\nlocal pack = table.pack or function(...) return { n = select('#', ...), ... } end\nlocal unpack = table.unpack or unpack\n\nlocal VM = {}\n\n-- Optional dynamic opcode profiler. When non-nil, the dispatch loop counts\n-- executed opcodes into it (one nil-check per instruction when disabled).\nlocal PROF = nil\nfunction VM.setProfile(counters) PROF = counters end\n\n-- Forward declaration: execute runs a proto with its upvalues/env/args.\nlocal execute\n\n-- Wrap a proto + captured upvalues + env into a callable Lua value.\nlocal function makeClosure(proto, upvals, env)\n  return function(...)\n    local args = pack(...)\n    local res = execute(proto, upvals, env, args, args.n)\n    return unpack(res, 1, res.n)\n  end\nend\n\n-- The interpreter. Returns a packed results table {..., n=}.\nexecute = function(proto, upvals, env, args, argN)\n  local code = proto.code\n  local K = proto.consts\n  local protos = proto.protos\n  local R = {}\n\n  local np = proto.numparams\n  for i = 0, np - 1 do R[i] = args[i + 1] end\n\n  local varargs, varargN = nil, 0\n  if proto.isVararg then\n    varargs = {}\n    for i = np + 1, argN do\n      varargN = varargN + 1\n      varargs[varargN] = args[i]\n    end\n  end\n\n  local top = 0\n  local pc = 1\n\n  while true do\n    local ins = code[pc]\n    pc = pc + 1\n    local op = ins.op\n    local a = ins.a\n    if PROF then PROF[op] = (PROF[op] or 0) + 1 end\n\n    -- Dispatch is ordered hottest-first: in a linear if/elseif chain each branch\n    -- costs one comparison, so the common ops (calls, arithmetic, compares,\n    -- jumps, moves, loads) are checked before the rare ones. See docs/perf.md.\n    if op == Op.MOVE then R[a] = R[ins.b]\n    elseif op == Op.CALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      local res = pack(fn(unpack(callArgs, 1, nargs)))\n      local c = ins.c\n      if c == 0 then\n        for i = 1, res.n do R[a + i - 1] = res[i] end\n        top = a + res.n\n      else\n        for i = 1, c - 1 do R[a + i - 1] = res[i] end\n      end\n    elseif op == Op.RETURN then\n      local b = ins.b\n      local nret = (b == 0) and (top - a) or (b - 1)\n      local out = {}\n      for i = 1, nret do out[i] = R[a + i - 1] end\n      out.n = nret\n      return out\n    elseif op == Op.ADD then R[a] = R[ins.b] + R[ins.c]\n    elseif op == Op.SUB then R[a] = R[ins.b] - R[ins.c]\n    elseif op == Op.LT then R[a] = (R[ins.b] < R[ins.c])\n    elseif op == Op.JMPIFNOT then if not R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMPIF then if R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMP then pc = pc + ins.sbx\n    elseif op == Op.LOADINT then R[a] = ins.sbx\n    elseif op == Op.LOADK then R[a] = K[ins.bx]\n    elseif op == Op.GETGLOBAL then R[a] = env[K[ins.bx]]\n    elseif op == Op.GETCELL then R[a] = R[ins.b].v\n    elseif op == Op.SETCELL then R[a].v = R[ins.b]\n    elseif op == Op.GETUPVAL then R[a] = upvals[ins.b].v\n    elseif op == Op.SETUPVAL then upvals[ins.b].v = R[a]\n    elseif op == Op.MUL then R[a] = R[ins.b] * R[ins.c]\n    elseif op == Op.LE then R[a] = (R[ins.b] <= R[ins.c])\n    elseif op == Op.EQ then R[a] = (R[ins.b] == R[ins.c])\n    elseif op == Op.GETFIELD then R[a] = R[ins.b][K[ins.bx]]\n    elseif op == Op.GETTABLE then R[a] = R[ins.b][R[ins.c]]\n    elseif op == Op.FORLOOP then\n      local step = R[a + 2]\n      local idx = R[a] + step\n      R[a] = idx\n      local limit = R[a + 1]\n      if (step >= 0 and idx <= limit) or (step < 0 and idx >= limit) then\n        R[a + 3] = idx\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.FORPREP then\n      R[a] = R[a] - R[a + 2]\n      pc = pc + ins.sbx\n\n    --  colder opcodes \n    elseif op == Op.SETTABLE then R[a][R[ins.b]] = R[ins.c]\n    elseif op == Op.SETFIELD then R[a][K[ins.bx]] = R[ins.c]\n    elseif op == Op.SETGLOBAL then env[K[ins.bx]] = R[a]\n    elseif op == Op.NEWTABLE then R[a] = {}\n    elseif op == Op.SELF then\n      R[a + 1] = R[ins.b]\n      R[a] = R[ins.b][K[ins.c]]\n    elseif op == Op.SETLIST then\n      local t = R[a]\n      local count = ins.b\n      if count == 0 then count = top - a - 1 end\n      local base = ins.c\n      for i = 1, count do t[base + i] = R[a + i] end\n    elseif op == Op.CLOSURE then\n      local child = protos[ins.bx]\n      local newUp = {}\n      for i, d in ipairs(child.upvals) do\n        if d.kind == 'reg' then newUp[i] = R[d.index]\n        else newUp[i] = upvals[d.index] end\n      end\n      R[a] = makeClosure(child, newUp, env)\n    elseif op == Op.VARARG then\n      local b = ins.b\n      local count = (b == 0) and varargN or (b - 1)\n      for i = 1, count do R[a + i - 1] = varargs[i] end\n      if b == 0 then top = a + varargN end\n    elseif op == Op.NEWCELL then R[a] = { v = R[a] }\n    elseif op == Op.LOADBOOL then R[a] = (ins.b ~= 0)\n    elseif op == Op.LOADNIL then for i = a, a + ins.b do R[i] = nil end\n    elseif op == Op.DIV then R[a] = R[ins.b] / R[ins.c]\n    elseif op == Op.MOD then R[a] = R[ins.b] % R[ins.c]\n    elseif op == Op.POW then R[a] = R[ins.b] ^ R[ins.c]\n    elseif op == Op.IDIV then R[a] = math.floor(R[ins.b] / R[ins.c])\n    elseif op == Op.BAND then R[a] = Bit.band(R[ins.b], R[ins.c])\n    elseif op == Op.BOR then R[a] = Bit.bor(R[ins.b], R[ins.c])\n    elseif op == Op.BXOR then R[a] = Bit.bxor(R[ins.b], R[ins.c])\n    elseif op == Op.SHL then R[a] = Bit.lshift(R[ins.b], R[ins.c])\n    elseif op == Op.SHR then R[a] = Bit.rshift(R[ins.b], R[ins.c])\n    elseif op == Op.CONCAT then\n      local s = R[ins.b]\n      for i = ins.b + 1, ins.c do s = s .. R[i] end\n      R[a] = s\n    elseif op == Op.UNM then R[a] = -R[ins.b]\n    elseif op == Op.NOT then R[a] = not R[ins.b]\n    elseif op == Op.LEN then R[a] = #R[ins.b]\n    elseif op == Op.BNOT then R[a] = Bit.bnot(R[ins.b])\n    elseif op == Op.TAILCALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      return pack(fn(unpack(callArgs, 1, nargs)))\n    elseif op == Op.TFORCALL then\n      local fn = R[a]\n      local res = pack(fn(R[a + 1], R[a + 2]))\n      for i = 1, ins.c do R[a + 2 + i] = res[i] end\n    elseif op == Op.TFORLOOP then\n      if R[a + 3] ~= nil then\n        R[a + 2] = R[a + 3]\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.NOP then -- nothing\n    else\n      error('ferret-vm: bad opcode ' .. Opcodes.mnemonic(op) .. ' at pc ' .. (pc - 1))\n    end\n  end\nend\n\n-- Public: build a callable from a top-level proto and an environment.\nfunction VM.load(proto, env)\n  env = env or _ENV or _G\n  return makeClosure(proto, {}, env)\nend\n\nVM.execute = execute\nVM.makeClosure = makeClosure\nreturn VM\n","api":"-- luau-vm/src/api.lua\n-- Convenience front end: source -> bytecode -> callable, with no loadstring.\n\nlocal Compiler = require('compiler')\nlocal VM = require('vm')\nlocal Serializer = require('serializer')\n\nlocal API = {}\n\nfunction API.compile(src, chunkName)\n  return Compiler.compile(src, chunkName)\nend\n\nfunction API.load(src, env, chunkName)\n  return VM.load(Compiler.compile(src, chunkName), env or _G)\nend\n\n-- Compile to a portable binary bytecode string (no loadstring on either side).\nfunction API.serialize(src, chunkName)\n  return Serializer.serialize(Compiler.compile(src, chunkName))\nend\n\n-- Load and run bytecode produced by API.serialize.\nfunction API.loadBytecode(bytes, env)\n  return VM.load(Serializer.deserialize(bytes), env or _G)\nend\n\nfunction API.run(src, env, chunkName, ...)\n  return API.load(src, env, chunkName)(...)\nend\n\nAPI.VM = VM\nAPI.Compiler = Compiler\nAPI.Serializer = Serializer\nreturn API\n","harden":"-- luau-vm/src/harden.lua\n-- Per-build hardening primitives for the VM bundler. These make two emitted\n-- builds of the same source differ, and raise the cost of a generic\n-- devirtualizer, without touching the (validated) compiler/VM core:\n--\n--   * opcode permutation   the serialized bytecode uses a per-build opcode\n--     numbering, so tooling keyed to the canonical opcode set can't read it.\n--   * bytecode encryption  a Park-Miller XOR keystream over the whole\n--     serialized blob, so a base64 decode no longer reveals the proto tables.\n--   * key factoring        the keystream seed is emitted as an arithmetic\n--     expression, not a single grep-able literal.\n--   * comment stripping    the bundled interpreter ships without its\n--     self-documenting comments, so opcode semantics aren't handed over.\n--\n-- None of this is unbreakable (no self-contained client-side obfuscator can\n-- be  the key and decoder must be present to run). It defeats automated /\n-- canned tooling and casual copy-paste, which is the realistic threat.\n\nlocal Bit = require('bitops')\n\nlocal H = {}\n\n-- Park-Miller minimal-standard LCG. Products stay < 2^53, so the sequence is\n-- identical in Lua 5.1-5.4 doubles AND Luau doubles (the same reason the ferret\n-- keystream uses it). Returns a stateful generator.\nfunction H.prng(seed)\n  local st = seed % 2147483647\n  if st <= 0 then st = st + 2147483646 end\n  return {\n    -- next raw state in [1, 2147483646]\n    next = function() st = (st * 16807) % 2147483647; return st end,\n    -- next integer in [0, n-1]\n    int = function(n) st = (st * 16807) % 2147483647; return st % n end,\n    -- next byte in [0, 255]\n    byte = function() st = (st * 16807) % 2147483647; return st % 256 end,\n  }\nend\n\n-- Build a per-build opcode permutation for `count` canonical opcodes (1..count).\n-- Returns fwd (canonical -> emitted byte) and inv (emitted byte -> canonical),\n-- each opcode mapped to a distinct byte in [1, 255].\nfunction H.opPermutation(count, rng)\n  local pool = {}\n  for b = 1, 255 do pool[b] = b end\n  -- Fisher-Yates shuffle the byte pool\n  for i = 255, 2, -1 do\n    local j = rng.int(i) + 1\n    pool[i], pool[j] = pool[j], pool[i]\n  end\n  local fwd, inv = {}, {}\n  for op = 1, count do\n    local b = pool[op]\n    fwd[op] = b\n    inv[b] = op\n  end\n  return fwd, inv\nend\n\n-- XOR `data` with a Park-Miller keystream seeded by `seed`. Symmetric: the\n-- emitted bootstrap runs the identical routine to decrypt.\nfunction H.encrypt(data, seed)\n  local rng = H.prng(seed)\n  local out, len = {}, #data\n  for i = 1, len do\n    out[i] = string.char(Bit.bxor(data:byte(i), rng.byte()))\n  end\n  return table.concat(out)\nend\n\n-- Emit `seed` as an arithmetic expression `(m*q+r)` rather than a bare literal,\n-- so the keystream seed is not directly grep-able in the output. Factors are\n-- kept < 2^31 so the product is exact in every target runtime.\nfunction H.factorKey(seed, rng)\n  local m = rng.int(40000) + 4096         -- 4096 .. 44095\n  local q = math.floor(seed / m)\n  local r = seed % m\n  return string.format('(%d*%d+%d)', m, q, r)  -- == m*q + r == seed\nend\n\n-- Render a { byte = canonical } Lua table literal (the inverse opcode map the\n-- bootstrap hands to the deserializer).\nfunction H.invMapLiteral(inv)\n  local parts = {}\n  for b, op in pairs(inv) do parts[#parts + 1] = string.format('[%d]=%d', b, op) end\n  return '{' .. table.concat(parts, ',') .. '}'\nend\n\n-- Strip Lua comments (line and long-bracket) and blank/whitespace-only lines\n-- from `src`, correctly skipping over string literals and long-bracket strings\n-- so code is never touched. Returns the stripped source. Callers should still\n-- guard the result with load() and fall back to the original on any surprise.\nfunction H.stripComments(src)\n  local out, i, n = {}, 1, #src\n  local function peek(k) return src:sub(i + (k or 0), i + (k or 0)) end\n  -- match a long-bracket opener at position i: returns level (>=0) or nil\n  local function longOpen()\n    if peek() ~= '[' then return nil end\n    local j, eq = i + 1, 0\n    while src:sub(j, j) == '=' do eq = eq + 1; j = j + 1 end\n    if src:sub(j, j) == '[' then return eq end\n    return nil\n  end\n  local function skipLong(eq)\n    local close = ']' .. string.rep('=', eq) .. ']'\n    local at = src:find(close, i, true)\n    return at and (at + #close) or (n + 1)\n  end\n  while i <= n do\n    local c = peek()\n    if c == '-' and peek(1) == '-' then\n      -- comment: long or line\n      i = i + 2\n      local eq = longOpen()\n      if eq ~= nil then\n        i = i + eq + 2\n        i = skipLong(eq)\n      else\n        while i <= n and src:sub(i, i) ~= '\\n' do i = i + 1 end\n      end\n    elseif c == '\"' or c == \"'\" then\n      out[#out + 1] = c; i = i + 1\n      while i <= n do\n        local d = src:sub(i, i)\n        out[#out + 1] = d; i = i + 1\n        if d == '\\\\' then out[#out + 1] = src:sub(i, i); i = i + 1\n        elseif d == c then break end\n      end\n    else\n      local eq = longOpen()\n      if eq ~= nil then\n        local from = i\n        i = i + eq + 2\n        local to = skipLong(eq)\n        out[#out + 1] = src:sub(from, to - 1)\n        i = to\n      else\n        out[#out + 1] = c; i = i + 1\n      end\n    end\n  end\n  -- drop trailing whitespace on each line and blank lines\n  local text = table.concat(out)\n  local kept = {}\n  for line in (text .. '\\n'):gmatch('([^\\n]*)\\n') do\n    local trimmed = line:gsub('%s+$', '')\n    if trimmed:match('%S') then kept[#kept + 1] = trimmed end\n  end\n  return table.concat(kept, '\\n')\nend\n\nreturn H\n","webbundle":"-- luau-vm/src/webbundle.lua\n-- Browser-friendly bundler: compile a Luau source string to a self-contained,\n-- HARDENED VM-protected script. Unlike tools/bundle.lua it never touches the\n-- filesystem; the runtime module sources are passed in (the website embeds\n-- them), so this runs unchanged inside Fengari (Lua-in-JS) in the browser.\n--\n-- Hardening applied per build (see harden.lua): opcode permutation, bytecode\n-- encryption (Park-Miller XOR keystream), a factored (non-literal) key, and\n-- comment-stripped runtime sources. Still no loadstring, and the original\n-- source is never reconstructed  the logic exists only as encrypted bytecode.\n\nlocal Compiler = require('compiler')\nlocal Serializer = require('serializer')\nlocal Opcodes = require('opcodes')\nlocal Harden = require('harden')\n\nlocal M = {}\n\nlocal B64 = 'ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'\nlocal function b64encode(data)\n  local out, len = {}, #data\n  for i = 1, len, 3 do\n    local b1 = data:byte(i)\n    local b2 = i + 1 <= len and data:byte(i + 1) or 0\n    local b3 = i + 2 <= len and data:byte(i + 2) or 0\n    local n = b1 * 65536 + b2 * 256 + b3\n    out[#out + 1] = B64:sub(math.floor(n / 262144) % 64 + 1, math.floor(n / 262144) % 64 + 1)\n    out[#out + 1] = B64:sub(math.floor(n / 4096) % 64 + 1, math.floor(n / 4096) % 64 + 1)\n    out[#out + 1] = i + 1 <= len and B64:sub(math.floor(n / 64) % 64 + 1, math.floor(n / 64) % 64 + 1) or '='\n    out[#out + 1] = i + 2 <= len and B64:sub(n % 64 + 1, n % 64 + 1) or '='\n  end\n  return table.concat(out)\nend\n\n-- Pick a per-build seed. Deterministic when opts.seed is given (tests); else\n-- derived from wall clock + math.random so each build differs.\nlocal function pickSeed(opts)\n  if opts and opts.seed then return opts.seed end\n  local t = (os and os.time and os.time()) or 0\n  local r = math.random(1, 2147483646)\n  local s = (t * 2654435761 + r) % 2147483647\n  if s <= 0 then s = s + 2147483646 end\n  return s\nend\n\n-- Strip comments from a runtime source, but only if the result still parses.\nlocal function safeStrip(src)\n  local stripped = Harden.stripComments(src)\n  local chunk = (loadstring or load)(stripped)\n  if chunk then return stripped end\n  return src\nend\n\n-- runtimeSrc: table of Lua source strings for { opcodes, bitops, serializer, vm }.\nfunction M.bundle(src, runtimeSrc, chunkName, opts)\n  local seed = pickSeed(opts)\n  local rng = Harden.prng(seed)\n\n  -- 1. compile, 2. permute opcodes, 3. serialize with the permutation,\n  -- 4. encrypt the whole blob with a keystream seeded off the same build seed.\n  local proto = Compiler.compile(src, chunkName or 'input')\n  local fwd, inv = Harden.opPermutation(Opcodes.count, rng)\n  local plain = Serializer.serialize(proto, fwd)\n  local cipherSeed = rng.next() % 2147483647\n  if cipherSeed <= 0 then cipherSeed = cipherSeed + 2147483646 end\n  local cipher = Harden.encrypt(plain, cipherSeed)\n  local payload = b64encode(cipher)\n\n  local keyExpr = Harden.factorKey(cipherSeed, rng)\n  local invLit = Harden.invMapLiteral(inv)\n\n  local order = { 'opcodes', 'bitops', 'serializer', 'vm' }\n  local parts = {}\n  -- banner (ASCII only  the browser build ASCII-sanitizes this source)\n  parts[#parts + 1] = '-- ================================================================'\n  parts[#parts + 1] = '--  Obfuscated by Granite Lock  |  https://granitelock.com'\n  parts[#parts + 1] = '--  Custom bytecode VM  |  encrypted  |  no loadstring'\n  parts[#parts + 1] = '-- ================================================================'\n  parts[#parts + 1] = 'local __m,__c={},{}'\n  parts[#parts + 1] = 'local function require(n) if __c[n]==nil then __c[n]=__m[n]() end return __c[n] end'\n  for _, name in ipairs(order) do\n    local s = runtimeSrc[name]\n    if not s then error('webbundle: missing runtime source for ' .. name) end\n    parts[#parts + 1] = \"__m['\" .. name .. \"']=function()\\n\" .. safeStrip(s) .. '\\nend'\n  end\n  -- base64 decoder + keystream decryptor + bootstrap\n  parts[#parts + 1] = table.concat({\n    \"local __A='\" .. B64 .. \"'\",\n    'local function __b64(s)',\n    '  local r,v,b={},0,0',\n    \"  s=s:gsub('[^'..__A..'=]','')\",\n    '  for i=1,#s do',\n    '    local c=s:sub(i,i)',\n    \"    if c=='=' then break end\",\n    '    local p=__A:find(c,1,true)',\n    '    if not p then break end',\n    '    v=v*64+(p-1) b=b+6',\n    '    if b>=8 then b=b-8 r[#r+1]=string.char(math.floor(v/2^b)%256) v=v%(2^b) end',\n    '  end',\n    '  return table.concat(r)',\n    'end',\n    'local __Bit=require(\"bitops\")',\n    'local function __dec(s)',\n    '  local st=' .. keyExpr,\n    '  local o={}',\n    '  for i=1,#s do st=(st*16807)%2147483647 o[i]=string.char(__Bit.bxor(s:byte(i),st%256)) end',\n    '  return table.concat(o)',\n    'end',\n    'local __INV=' .. invLit,\n    'local __Ser=require(\"serializer\")',\n    'local __VM=require(\"vm\")',\n    'local __proto=__Ser.deserialize(__dec(__b64(__PAYLOAD__)),__INV)',\n    -- Resolve the global environment for the VM. Roblox Luau has no _ENV, so we\n    -- prefer an explicit _ENV where a runtime provides one (Lua 5.2+), else the\n    -- Roblox/5.1 getfenv (pcall-guarded so a sandbox that errors on it can't\n    -- break loading), else _G. getfenv appears only here in the tiny bootstrap,\n    -- never in the interpreter loop, so Luau's getfenv deopt doesn't touch hot code.\n    'local __env',\n    'if type(_ENV)==\"table\" then __env=_ENV',\n    'elseif getfenv then local __ok,__e=pcall(getfenv,1) __env=(__ok and type(__e)==\"table\") and __e or _G',\n    'else __env=_G end',\n    'return __VM.load(__proto,__env)()',\n  }, '\\n')\n  local body = table.concat(parts, '\\n')\n  local out = body:gsub('__PAYLOAD__', function() return \"'\" .. payload .. \"'\" end)\n  return out\nend\n\nreturn M\n"};
window.LUAU_VM_RUNTIME={"opcodes":"-- luau-vm/src/opcodes.lua\n-- Custom instruction set for the ferret VM.\n--\n-- Register-based. Operands are register indices unless noted. Multi-value\n-- calls/returns/varargs follow a Lua-style convention: a count field of 0 means\n-- \"up to the current frame top\" (set by a preceding multi-value producer), and\n-- a result count of 0 means \"produce all results and set top\". Everything else\n-- uses exact counts, which keeps the common case simple and fast.\n--\n-- Instructions are stored at compile time as tables {op=, a=, b=, c=, bx=, sbx=}\n-- for readability; the serializer packs them into a compact binary form.\n--\n-- Captured locals and upvalues are unified as \"cells\" (a 1-field box {v=...}),\n-- so closures never touch the parent's live registers  no open/closed upvalue\n-- machinery is required.\n\nlocal Op = {}\nlocal names = {}\nlocal n = 0\nlocal function def(name)\n  n = n + 1\n  Op[name] = n\n  names[n] = name\n  return n\nend\n\n--  data movement / constants \ndef('MOVE')      -- A B      R[A] = R[B]\ndef('LOADK')     -- A Bx     R[A] = K[Bx]\ndef('LOADINT')   -- A sBx    R[A] = sBx                (immediate small integer)\ndef('LOADBOOL')  -- A B      R[A] = (B ~= 0)\ndef('LOADNIL')   -- A B      R[A..A+B] = nil\n\n--  globals / environment \ndef('GETGLOBAL') -- A Bx     R[A] = ENV[K[Bx]]\ndef('SETGLOBAL') -- A Bx     ENV[K[Bx]] = R[A]\n\n--  cells (captured locals) & upvalues \ndef('NEWCELL')   -- A        R[A] = { v = R[A] }       (box a captured local)\ndef('GETCELL')   -- A B      R[A] = R[B].v\ndef('SETCELL')   -- A B      R[A].v = R[B]\ndef('GETUPVAL')  -- A B      R[A] = U[B].v\ndef('SETUPVAL')  -- A B      U[B].v = R[A]\n\n--  tables \ndef('NEWTABLE')  -- A        R[A] = {}\ndef('GETTABLE')  -- A B C    R[A] = R[B][R[C]]\ndef('SETTABLE')  -- A B C    R[A][R[B]] = R[C]\ndef('GETFIELD')  -- A B Bx   R[A] = R[B][K[Bx]]        (const-string key fast path)\ndef('SETFIELD')  -- A Bx C   R[A][K[Bx]] = R[C]\ndef('SELF')      -- A B C    R[A+1] = R[B]; R[A] = R[B][K[C]]  (method prep)\ndef('SETLIST')   -- A B C    R[A][C + i] = R[A+i], i=1..B (B=0 -> up to top)\n\n--  arithmetic (R[A] = R[B] op R[C]) \ndef('ADD'); def('SUB'); def('MUL'); def('DIV'); def('MOD'); def('POW'); def('IDIV')\n--  bitwise \ndef('BAND'); def('BOR'); def('BXOR'); def('SHL'); def('SHR')\n--  concat \ndef('CONCAT')    -- A B C    R[A] = R[B] .. R[B+1] .. ... .. R[C]\n--  unary \ndef('UNM'); def('NOT'); def('LEN'); def('BNOT')  -- A B   R[A] = op R[B]\n--  comparison (R[A] = R[B] op R[C]) \ndef('EQ'); def('LT'); def('LE')\n\n--  control flow \ndef('JMP')       -- sBx      pc += sBx\ndef('JMPIF')     -- A sBx    if truthy(R[A]) then pc += sBx\ndef('JMPIFNOT')  -- A sBx    if not truthy(R[A]) then pc += sBx\n\n--  calls / returns \ndef('CALL')      -- A B C    call R[A] with (B-1) args; keep (C-1) results (0 = to top)\ndef('TAILCALL')  -- A B      return R[A]((B-1) args)   (no host TCO; result-preserving)\ndef('RETURN')    -- A B      return R[A..A+B-2]        (B=0 -> to top)\n\n--  closures / varargs \ndef('CLOSURE')   -- A Bx     R[A] = closure(protos[Bx], captured upvals)\ndef('VARARG')    -- A B      R[A..A+B-2] = varargs     (B=0 -> to top)\n\n--  loops \ndef('FORPREP')   -- A sBx    numeric-for init; jump to loop test\ndef('FORLOOP')   -- A sBx    numeric-for step + test; jump back if continuing\ndef('TFORCALL')  -- A C      generic-for: call iterator, C results into R[A+3..]\ndef('TFORLOOP')  -- A sBx    generic-for: if R[A+1] ~= nil then R[A]=R[A+1]; pc += sBx\n\ndef('NOP')       -- (used by peephole/DCE)\n\n-- Operand layout per opcode: which instruction fields carry data. Used by the\n-- serializer for a compact, self-validating encoding, and as documentation.\nlocal A, AB, ABC = { 'a' }, { 'a', 'b' }, { 'a', 'b', 'c' }\nlocal operands = {\n  [Op.MOVE] = AB, [Op.LOADK] = { 'a', 'bx' }, [Op.LOADINT] = { 'a', 'sbx' },\n  [Op.LOADBOOL] = AB, [Op.LOADNIL] = AB,\n  [Op.GETGLOBAL] = { 'a', 'bx' }, [Op.SETGLOBAL] = { 'a', 'bx' },\n  [Op.NEWCELL] = A, [Op.GETCELL] = AB, [Op.SETCELL] = AB, [Op.GETUPVAL] = AB, [Op.SETUPVAL] = AB,\n  [Op.NEWTABLE] = A, [Op.GETTABLE] = ABC, [Op.SETTABLE] = ABC,\n  [Op.GETFIELD] = { 'a', 'b', 'bx' }, [Op.SETFIELD] = { 'a', 'bx', 'c' },\n  [Op.SELF] = ABC, [Op.SETLIST] = ABC,\n  [Op.ADD] = ABC, [Op.SUB] = ABC, [Op.MUL] = ABC, [Op.DIV] = ABC, [Op.MOD] = ABC,\n  [Op.POW] = ABC, [Op.IDIV] = ABC,\n  [Op.BAND] = ABC, [Op.BOR] = ABC, [Op.BXOR] = ABC, [Op.SHL] = ABC, [Op.SHR] = ABC,\n  [Op.CONCAT] = ABC,\n  [Op.UNM] = AB, [Op.NOT] = AB, [Op.LEN] = AB, [Op.BNOT] = AB,\n  [Op.EQ] = ABC, [Op.LT] = ABC, [Op.LE] = ABC,\n  [Op.JMP] = { 'sbx' }, [Op.JMPIF] = { 'a', 'sbx' }, [Op.JMPIFNOT] = { 'a', 'sbx' },\n  [Op.CALL] = ABC, [Op.TAILCALL] = AB, [Op.RETURN] = AB,\n  [Op.CLOSURE] = { 'a', 'bx' }, [Op.VARARG] = AB,\n  [Op.FORPREP] = { 'a', 'sbx' }, [Op.FORLOOP] = { 'a', 'sbx' },\n  [Op.TFORCALL] = { 'a', 'c' }, [Op.TFORLOOP] = { 'a', 'sbx' },\n  [Op.NOP] = {},\n}\n\nlocal Opcodes = { Op = Op, name = names, count = n, operands = operands }\n\nfunction Opcodes.mnemonic(op)\n  return names[op] or ('?' .. tostring(op))\nend\n\nreturn Opcodes\n","bitops":"-- luau-vm/src/bitops.lua\n-- Portable 32-bit bitwise ops. Uses bit32 when present (Luau, Lua 5.2); falls\n-- back to arithmetic otherwise (Lua 5.4 removed both bit32 and  crucially for\n-- source portability  we cannot write &|~<<>> operators in code that must also\n-- parse under Luau). 32-bit (bit32) semantics; document accordingly.\n\nlocal M = {}\n\nif bit32 then\n  M.band = bit32.band\n  M.bor = bit32.bor\n  M.bxor = bit32.bxor\n  M.lshift = bit32.lshift\n  M.rshift = bit32.rshift\n  M.bnot = bit32.bnot\nelse\n  local TWO32 = 4294967296\n  local function norm(x) x = math.floor(x) % TWO32; return x end\n  local function binop(a, b, f)\n    a = norm(a); b = norm(b)\n    local r, p = 0, 1\n    for _ = 0, 31 do\n      local x, y = a % 2, b % 2\n      if f(x, y) == 1 then r = r + p end\n      a = (a - x) / 2; b = (b - y) / 2; p = p * 2\n    end\n    return r\n  end\n  function M.band(a, b) return binop(a, b, function(x, y) return (x == 1 and y == 1) and 1 or 0 end) end\n  function M.bor(a, b) return binop(a, b, function(x, y) return (x == 1 or y == 1) and 1 or 0 end) end\n  function M.bxor(a, b) return binop(a, b, function(x, y) return (x ~= y) and 1 or 0 end) end\n  function M.lshift(a, n) return norm(norm(a) * (2 ^ n)) end\n  function M.rshift(a, n) return math.floor(norm(a) / (2 ^ n)) end\n  function M.bnot(a) return (TWO32 - 1) - norm(a) end\nend\n\nreturn M\n","serializer":"-- luau-vm/src/serializer.lua\n-- Compact binary encoding of a compiled proto tree, and its inverse loader.\n-- No loadstring: bytes -> runtime proto tables directly.\n--\n-- Format\n--   magic  'FVM' , version(1 byte)\n--   uint32 checksum (FNV-1a over the body)\n--   uint32 bodyLength\n--   body:  proto (recursive)\n-- Integers use zig-zag LEB128 varints; numbers round-trip via %.17g text so no\n-- string.pack dependency (works on Lua 5.1+/Luau uniformly).\n\nlocal Opcodes = require('opcodes')\nlocal Bit = require('bitops')\n\nlocal Serializer = {}\n\nlocal MAGIC = 'FVM'\nlocal VERSION = 1\n\n--  writer \nlocal function Writer()\n  return { buf = {}, put = function(self, s) self.buf[#self.buf + 1] = s end }\nend\nlocal function writeByte(w, b) w:put(string.char(b % 256)) end\nlocal function writeUVarint(w, x)\n  x = math.floor(x)\n  while true do\n    local b = x % 128\n    x = math.floor(x / 128)\n    if x > 0 then writeByte(w, b + 128) else writeByte(w, b); break end\n  end\nend\nlocal function writeSVarint(w, x)\n  x = math.floor(x)\n  local zz = x >= 0 and (x * 2) or (-x * 2 - 1) -- zig-zag\n  writeUVarint(w, zz)\nend\nlocal function writeString(w, s)\n  writeUVarint(w, #s)\n  w:put(s)\nend\nlocal function writeU32(w, x)\n  x = math.floor(x) % 4294967296\n  for _ = 1, 4 do writeByte(w, x % 256); x = math.floor(x / 256) end\nend\n\n--  reader \nlocal function Reader(s) return { s = s, pos = 1 } end\n-- EOF-safe: a truncated/corrupt stream reports its position instead of faulting\n-- later on a nil (e.g. `nil % 128`). Keeps malformed input from crashing the host.\nlocal function readByte(r)\n  local b = string.byte(r.s, r.pos)\n  if b == nil then error('serializer: unexpected end of bytecode at offset ' .. r.pos) end\n  r.pos = r.pos + 1\n  return b\nend\nlocal function readUVarint(r)\n  local x, shift = 0, 1\n  while true do\n    local b = readByte(r)\n    x = x + (b % 128) * shift\n    if b < 128 then break end\n    shift = shift * 128\n  end\n  return x\nend\nlocal function readSVarint(r)\n  local zz = readUVarint(r)\n  -- math.floor keeps an integer subtype on Lua 5.4 (unlike `/`, which floats)\n  if zz % 2 == 0 then return math.floor(zz / 2) else return -math.floor((zz + 1) / 2) end\nend\nlocal function readString(r)\n  local n = readUVarint(r)\n  local s = r.s:sub(r.pos, r.pos + n - 1)\n  r.pos = r.pos + n\n  return s\nend\nlocal function readU32(r)\n  local x, m = 0, 1\n  for _ = 1, 4 do x = x + readByte(r) * m; m = m * 256 end\n  return x\nend\n\n--  value (constant) encoding \nlocal T_NIL, T_TRUE, T_FALSE, T_INT, T_NUM, T_STR = 0, 1, 2, 3, 4, 5\nlocal function writeValue(w, v)\n  local t = type(v)\n  if v == nil then writeByte(w, T_NIL)\n  elseif v == true then writeByte(w, T_TRUE)\n  elseif v == false then writeByte(w, T_FALSE)\n  elseif t == 'number' then\n    if math.floor(v) == v and v >= -2147483648 and v <= 2147483647 then\n      writeByte(w, T_INT); writeSVarint(w, v)\n    else\n      writeByte(w, T_NUM); writeString(w, string.format('%.17g', v))\n    end\n  elseif t == 'string' then writeByte(w, T_STR); writeString(w, v)\n  else error('serializer: cannot encode constant of type ' .. t) end\nend\nlocal function readValue(r)\n  local t = readByte(r)\n  if t == T_NIL then return nil\n  elseif t == T_TRUE then return true\n  elseif t == T_FALSE then return false\n  elseif t == T_INT then return readSVarint(r)\n  elseif t == T_NUM then return tonumber(readString(r))\n  elseif t == T_STR then return readString(r)\n  else error('serializer: bad constant tag ' .. tostring(t)) end\nend\n\n--  proto encoding \n-- opMap (optional): canonical opcode -> the byte written for it. Lets a build\n-- ship a per-build opcode numbering so the bytecode can't be read by a\n-- devirtualizer keyed to the canonical set. ins.op stays canonical internally,\n-- so operand-layout lookup and the VM's dispatch are unaffected.\nlocal function writeProto(w, p, opMap)\n  writeUVarint(w, p.numparams)\n  writeByte(w, p.isVararg and 1 or 0)\n  writeUVarint(w, p.maxstack)\n  -- upvalues\n  writeUVarint(w, #p.upvals)\n  for _, d in ipairs(p.upvals) do\n    writeByte(w, d.kind == 'reg' and 0 or 1)\n    writeUVarint(w, d.index)\n  end\n  -- constants\n  writeUVarint(w, #p.consts)\n  for _, c in ipairs(p.consts) do writeValue(w, c) end\n  -- code\n  writeUVarint(w, #p.code)\n  for _, ins in ipairs(p.code) do\n    writeByte(w, opMap and opMap[ins.op] or ins.op)\n    for _, field in ipairs(Opcodes.operands[ins.op]) do\n      writeSVarint(w, ins[field] or 0)\n    end\n  end\n  -- nested protos\n  writeUVarint(w, #p.protos)\n  for _, child in ipairs(p.protos) do writeProto(w, child, opMap) end\nend\n\n-- invMap (optional): the inverse of opMap (written byte -> canonical opcode).\nlocal function readProto(r, invMap)\n  local p = { upvals = {}, consts = {}, code = {}, protos = {}, lines = {} }\n  p.numparams = readUVarint(r)\n  p.isVararg = readByte(r) == 1\n  p.maxstack = readUVarint(r)\n  for i = 1, readUVarint(r) do\n    local kind = readByte(r) == 0 and 'reg' or 'up'\n    p.upvals[i] = { kind = kind, index = readUVarint(r) }\n  end\n  for i = 1, readUVarint(r) do p.consts[i] = readValue(r) end\n  local ncode = readUVarint(r)\n  for i = 1, ncode do\n    local op = readByte(r)\n    if invMap then op = invMap[op] end\n    local ins = { op = op }\n    for _, field in ipairs(Opcodes.operands[op]) do ins[field] = readSVarint(r) end\n    p.code[i] = ins\n  end\n  for i = 1, readUVarint(r) do p.protos[i] = readProto(r, invMap) end\n  return p\nend\n\n--  FNV-1a checksum (32-bit, portable) \nlocal function fnv1a(s)\n  local h = 2166136261\n  for i = 1, #s do\n    h = Bit.bxor(h, s:byte(i))\n    -- h * 16777619 mod 2^32, split to stay exact in doubles\n    local lo = (h % 65536) * 16777619\n    local hi = (math.floor(h / 65536) * 16777619) % 65536\n    h = (lo + hi * 65536) % 4294967296\n  end\n  return math.floor(h)\nend\n\n--  public API \nfunction Serializer.serialize(proto, opMap)\n  local w = Writer()\n  writeProto(w, proto, opMap)\n  local body = table.concat(w.buf)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, fnv1a(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nfunction Serializer.deserialize(bytes, invMap)\n  local r = Reader(bytes)\n  if bytes:sub(1, 3) ~= MAGIC then error('serializer: bad magic (not ferret bytecode)') end\n  r.pos = 4\n  local version = readByte(r)\n  if version ~= VERSION then error('serializer: unsupported version ' .. version) end\n  local checksum = readU32(r)\n  local bodyLen = readU32(r)\n  local body = bytes:sub(r.pos, r.pos + bodyLen - 1)\n  if fnv1a(body) ~= checksum then error('serializer: checksum mismatch (corrupt bytecode)') end\n  local br = Reader(body)\n  return readProto(br, invMap)\nend\n\n-- Recompute the container checksum over the current body. Lets tooling (e.g.\n-- the malformed-bytecode fuzzer) craft *well-formed-but-nonsense* bytecode that\n-- passes the checksum, so the structural validator  not the checksum  is what\n-- must catch it. Returns a resealed container the loader will accept.\nfunction Serializer.reseal(bytes)\n  local body = bytes:sub(13) -- MAGIC(3)+VERSION(1)+checksum(4)+bodyLen(4)\n  local head = Writer()\n  head:put(MAGIC)\n  writeByte(head, VERSION)\n  writeU32(head, fnv1a(body))\n  writeU32(head, #body)\n  return table.concat(head.buf) .. body\nend\n\nSerializer.MAGIC = MAGIC\nSerializer.VERSION = VERSION\nreturn Serializer\n","vm":"-- luau-vm/src/vm.lua\n-- Register-based interpreter for the ferret custom bytecode.\n--\n-- Design choices that buy correctness + Luau compatibility cheaply:\n--   * A VM closure is a REAL Lua function (see makeClosure) that runs `execute`.\n--     So VM and host functions are invoked identically, and metamethods, pcall,\n--     coroutines, table.sort(cmp), etc. all work because a compiled function is\n--     an ordinary callable Lua value.\n--   * All operators use the host's native ops (R[b] + R[c], R[b][k], #x, ..),\n--     so metatables (__index/__add/__concat/__len/) are honored by the host.\n--   * Captured locals & upvalues are \"cells\" ({v=...}); closures capture cell\n--     references, so no open/closed-upvalue bookkeeping is needed.\n--\n-- table.pack/unpack carry multiple values across call boundaries, so multiple\n-- returns and varargs are exact.\n\nlocal Opcodes = require('opcodes')\nlocal Bit = require('bitops')\nlocal Op = Opcodes.Op\n\nlocal pack = table.pack or function(...) return { n = select('#', ...), ... } end\nlocal unpack = table.unpack or unpack\n\nlocal VM = {}\n\n-- Optional dynamic opcode profiler. When non-nil, the dispatch loop counts\n-- executed opcodes into it (one nil-check per instruction when disabled).\nlocal PROF = nil\nfunction VM.setProfile(counters) PROF = counters end\n\n-- Forward declaration: execute runs a proto with its upvalues/env/args.\nlocal execute\n\n-- Wrap a proto + captured upvalues + env into a callable Lua value.\nlocal function makeClosure(proto, upvals, env)\n  return function(...)\n    local args = pack(...)\n    local res = execute(proto, upvals, env, args, args.n)\n    return unpack(res, 1, res.n)\n  end\nend\n\n-- The interpreter. Returns a packed results table {..., n=}.\nexecute = function(proto, upvals, env, args, argN)\n  local code = proto.code\n  local K = proto.consts\n  local protos = proto.protos\n  local R = {}\n\n  local np = proto.numparams\n  for i = 0, np - 1 do R[i] = args[i + 1] end\n\n  local varargs, varargN = nil, 0\n  if proto.isVararg then\n    varargs = {}\n    for i = np + 1, argN do\n      varargN = varargN + 1\n      varargs[varargN] = args[i]\n    end\n  end\n\n  local top = 0\n  local pc = 1\n\n  while true do\n    local ins = code[pc]\n    pc = pc + 1\n    local op = ins.op\n    local a = ins.a\n    if PROF then PROF[op] = (PROF[op] or 0) + 1 end\n\n    -- Dispatch is ordered hottest-first: in a linear if/elseif chain each branch\n    -- costs one comparison, so the common ops (calls, arithmetic, compares,\n    -- jumps, moves, loads) are checked before the rare ones. See docs/perf.md.\n    if op == Op.MOVE then R[a] = R[ins.b]\n    elseif op == Op.CALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      local res = pack(fn(unpack(callArgs, 1, nargs)))\n      local c = ins.c\n      if c == 0 then\n        for i = 1, res.n do R[a + i - 1] = res[i] end\n        top = a + res.n\n      else\n        for i = 1, c - 1 do R[a + i - 1] = res[i] end\n      end\n    elseif op == Op.RETURN then\n      local b = ins.b\n      local nret = (b == 0) and (top - a) or (b - 1)\n      local out = {}\n      for i = 1, nret do out[i] = R[a + i - 1] end\n      out.n = nret\n      return out\n    elseif op == Op.ADD then R[a] = R[ins.b] + R[ins.c]\n    elseif op == Op.SUB then R[a] = R[ins.b] - R[ins.c]\n    elseif op == Op.LT then R[a] = (R[ins.b] < R[ins.c])\n    elseif op == Op.JMPIFNOT then if not R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMPIF then if R[a] then pc = pc + ins.sbx end\n    elseif op == Op.JMP then pc = pc + ins.sbx\n    elseif op == Op.LOADINT then R[a] = ins.sbx\n    elseif op == Op.LOADK then R[a] = K[ins.bx]\n    elseif op == Op.GETGLOBAL then R[a] = env[K[ins.bx]]\n    elseif op == Op.GETCELL then R[a] = R[ins.b].v\n    elseif op == Op.SETCELL then R[a].v = R[ins.b]\n    elseif op == Op.GETUPVAL then R[a] = upvals[ins.b].v\n    elseif op == Op.SETUPVAL then upvals[ins.b].v = R[a]\n    elseif op == Op.MUL then R[a] = R[ins.b] * R[ins.c]\n    elseif op == Op.LE then R[a] = (R[ins.b] <= R[ins.c])\n    elseif op == Op.EQ then R[a] = (R[ins.b] == R[ins.c])\n    elseif op == Op.GETFIELD then R[a] = R[ins.b][K[ins.bx]]\n    elseif op == Op.GETTABLE then R[a] = R[ins.b][R[ins.c]]\n    elseif op == Op.FORLOOP then\n      local step = R[a + 2]\n      local idx = R[a] + step\n      R[a] = idx\n      local limit = R[a + 1]\n      if (step >= 0 and idx <= limit) or (step < 0 and idx >= limit) then\n        R[a + 3] = idx\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.FORPREP then\n      R[a] = R[a] - R[a + 2]\n      pc = pc + ins.sbx\n\n    --  colder opcodes \n    elseif op == Op.SETTABLE then R[a][R[ins.b]] = R[ins.c]\n    elseif op == Op.SETFIELD then R[a][K[ins.bx]] = R[ins.c]\n    elseif op == Op.SETGLOBAL then env[K[ins.bx]] = R[a]\n    elseif op == Op.NEWTABLE then R[a] = {}\n    elseif op == Op.SELF then\n      R[a + 1] = R[ins.b]\n      R[a] = R[ins.b][K[ins.c]]\n    elseif op == Op.SETLIST then\n      local t = R[a]\n      local count = ins.b\n      if count == 0 then count = top - a - 1 end\n      local base = ins.c\n      for i = 1, count do t[base + i] = R[a + i] end\n    elseif op == Op.CLOSURE then\n      local child = protos[ins.bx]\n      local newUp = {}\n      for i, d in ipairs(child.upvals) do\n        if d.kind == 'reg' then newUp[i] = R[d.index]\n        else newUp[i] = upvals[d.index] end\n      end\n      R[a] = makeClosure(child, newUp, env)\n    elseif op == Op.VARARG then\n      local b = ins.b\n      local count = (b == 0) and varargN or (b - 1)\n      for i = 1, count do R[a + i - 1] = varargs[i] end\n      if b == 0 then top = a + varargN end\n    elseif op == Op.NEWCELL then R[a] = { v = R[a] }\n    elseif op == Op.LOADBOOL then R[a] = (ins.b ~= 0)\n    elseif op == Op.LOADNIL then for i = a, a + ins.b do R[i] = nil end\n    elseif op == Op.DIV then R[a] = R[ins.b] / R[ins.c]\n    elseif op == Op.MOD then R[a] = R[ins.b] % R[ins.c]\n    elseif op == Op.POW then R[a] = R[ins.b] ^ R[ins.c]\n    elseif op == Op.IDIV then R[a] = math.floor(R[ins.b] / R[ins.c])\n    elseif op == Op.BAND then R[a] = Bit.band(R[ins.b], R[ins.c])\n    elseif op == Op.BOR then R[a] = Bit.bor(R[ins.b], R[ins.c])\n    elseif op == Op.BXOR then R[a] = Bit.bxor(R[ins.b], R[ins.c])\n    elseif op == Op.SHL then R[a] = Bit.lshift(R[ins.b], R[ins.c])\n    elseif op == Op.SHR then R[a] = Bit.rshift(R[ins.b], R[ins.c])\n    elseif op == Op.CONCAT then\n      local s = R[ins.b]\n      for i = ins.b + 1, ins.c do s = s .. R[i] end\n      R[a] = s\n    elseif op == Op.UNM then R[a] = -R[ins.b]\n    elseif op == Op.NOT then R[a] = not R[ins.b]\n    elseif op == Op.LEN then R[a] = #R[ins.b]\n    elseif op == Op.BNOT then R[a] = Bit.bnot(R[ins.b])\n    elseif op == Op.TAILCALL then\n      local fn = R[a]\n      local b = ins.b\n      local nargs = (b == 0) and (top - a - 1) or (b - 1)\n      local callArgs = {}\n      for i = 1, nargs do callArgs[i] = R[a + i] end\n      return pack(fn(unpack(callArgs, 1, nargs)))\n    elseif op == Op.TFORCALL then\n      local fn = R[a]\n      local res = pack(fn(R[a + 1], R[a + 2]))\n      for i = 1, ins.c do R[a + 2 + i] = res[i] end\n    elseif op == Op.TFORLOOP then\n      if R[a + 3] ~= nil then\n        R[a + 2] = R[a + 3]\n        pc = pc + ins.sbx\n      end\n    elseif op == Op.NOP then -- nothing\n    else\n      error('ferret-vm: bad opcode ' .. Opcodes.mnemonic(op) .. ' at pc ' .. (pc - 1))\n    end\n  end\nend\n\n-- Public: build a callable from a top-level proto and an environment.\nfunction VM.load(proto, env)\n  env = env or _ENV or _G\n  return makeClosure(proto, {}, env)\nend\n\nVM.execute = execute\nVM.makeClosure = makeClosure\nreturn VM\n"};
